import React, { useState, useRef, useEffect } from 'react';
import HouseCard from './components/HouseCard';
import LoginForm from './components/LoginForm';
import { HOUSES } from './constants';

const App: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const activeHouse = HOUSES[activeIndex];

  const handleNext = () => {
    setActiveIndex((prev) => (prev + 1) % HOUSES.length);
  };

  const handlePrev = () => {
    setActiveIndex((prev) => (prev - 1 + HOUSES.length) % HOUSES.length);
  };

  useEffect(() => {
    if (scrollRef.current) {
        const activeElement = scrollRef.current.children[activeIndex] as HTMLElement;
        if (activeElement) {
            const containerWidth = scrollRef.current.offsetWidth;
            const elementOffset = activeElement.offsetLeft;
            const elementWidth = activeElement.offsetWidth;

            scrollRef.current.scrollTo({
                left: elementOffset - (containerWidth / 2) + (elementWidth / 2),
                behavior: 'smooth'
            });
        }
    }
  }, [activeIndex]);

  if (isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center text-white px-4">
        <div className="max-w-xl text-center">
            <h1 className="text-5xl font-bold mb-6 tracking-tighter">Access Granted.</h1>
            <p className="text-xl text-white/60 mb-8 leading-relaxed">
                Welcome to <span className="text-white font-semibold">{activeHouse.name}</span> management portal.
                Your smart home dashboard is initializing.
            </p>
            <button 
                onClick={() => setIsLoggedIn(false)}
                className="px-8 py-3 glass rounded-full hover:bg-white/10 transition-all"
            >
                Secure Logout
            </button>
        </div>
      </div>
    );
  }

  return (
    <div className="relative min-h-screen w-full overflow-hidden bg-[#050505]">
      {/* Dynamic Background */}
      <div className="absolute inset-0 transition-all duration-1000 ease-in-out">
        {HOUSES.map((house, idx) => (
          <div
            key={house.id}
            className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${idx === activeIndex ? 'opacity-40 scale-105' : 'opacity-0 scale-100'}`}
            style={{
              backgroundImage: `url(${house.imageUrl})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
            }}
          />
        ))}
        {/* Dark Overlays & Vignette */}
        <div className="absolute inset-0 bg-gradient-to-b from-black/80 via-black/40 to-black" />
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.8)_100%)]" />
      </div>

      {/* Main Content Layout */}
      <div className="relative z-10 flex flex-col min-h-screen">
        {/* Header */}
        <header className="px-6 py-8 md:px-12 flex justify-between items-center">
          <div className="flex items-center gap-2 group cursor-pointer">
            <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center group-hover:rotate-12 transition-transform duration-500">
               <svg className="w-6 h-6 text-black" fill="currentColor" viewBox="0 0 24 24">
                   <path d="M12 3L4 9v12h5v-7h6v7h5V9l-8-6z" />
               </svg>
            </div>
            <span className="text-white font-display text-xl font-bold tracking-widest uppercase">LuxeHome</span>
          </div>
          <nav className="hidden md:flex gap-8">
            <a href="#" className="text-white/50 hover:text-white transition-colors text-sm uppercase tracking-widest">Properties</a>
            <a href="#" className="text-white/50 hover:text-white transition-colors text-sm uppercase tracking-widest">Support</a>
            <a href="#" className="text-white/50 hover:text-white transition-colors text-sm uppercase tracking-widest">Security</a>
          </nav>
        </header>

        {/* Center Content: Login Section */}
        <main className="flex-grow flex items-center justify-center px-4 py-12">
           <LoginForm 
              selectedHouseName={activeHouse.name} 
              onLogin={(email) => setIsLoggedIn(true)} 
           />
        </main>

        {/* Footer Content: Carousel Selection */}
        <div className="pb-16 pt-8 bg-gradient-to-t from-black via-black/80 to-transparent">
          <div className="max-w-7xl mx-auto px-4">
            <div className="flex items-center justify-between mb-8 px-4">
               <div>
                  <h2 className="text-white font-display text-lg font-bold tracking-wide">Select Your Domain</h2>
                  <p className="text-white/40 text-xs uppercase tracking-widest mt-1">Smart Key Access Required</p>
               </div>
               <div className="flex gap-4">
                  <button 
                    onClick={handlePrev}
                    className="w-12 h-12 rounded-full glass border border-white/10 flex items-center justify-center hover:bg-white/10 transition-all text-white group"
                  >
                    <svg className="w-6 h-6 transform group-active:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
                    </svg>
                  </button>
                  <button 
                    onClick={handleNext}
                    className="w-12 h-12 rounded-full glass border border-white/10 flex items-center justify-center hover:bg-white/10 transition-all text-white group"
                  >
                    <svg className="w-6 h-6 transform group-active:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                    </svg>
                  </button>
               </div>
            </div>

            {/* Horizontal Carousel */}
            <div 
              ref={scrollRef}
              className="flex items-center gap-8 overflow-x-auto pb-8 pt-12 scroll-smooth no-scrollbar px-[10%] md:px-[20%] lg:px-[30%]"
            >
              {HOUSES.map((house, index) => (
                <HouseCard
                  key={house.id}
                  house={house}
                  isActive={index === activeIndex}
                  onClick={() => setActiveIndex(index)}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

