export default LoginForm;

import React, { useState, useEffect, useCallback } from 'react';
import LoginForm from './components/LoginForm';
import { HOUSES } from './constants';

const App: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [direction, setDirection] = useState<'next' | 'prev' | null>(null);

  const activeHouse = HOUSES[activeIndex];

  const handleNext = useCallback(() => {
    setDirection('next');
    setActiveIndex((prev) => (prev + 1) % HOUSES.length);
  }, []);

  const handlePrev = useCallback(() => {
    setDirection('prev');
    setActiveIndex((prev) => (prev - 1 + HOUSES.length) % HOUSES.length);
  }, []);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight') handleNext();
      if (e.key === 'ArrowLeft') handlePrev();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNext, handlePrev]);

  if (isLoggedIn) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center text-white px-4">
        {/* Simple success background */}
        <div className="absolute inset-0 opacity-20 grayscale" style={{ backgroundImage: `url(${activeHouse.imageUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' }} />
        <div className="max-w-xl text-center relative z-10">
            <div className="mb-8 inline-block p-4 bg-white/10 rounded-full glass animate-bounce">
                <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                </svg>
            </div>
            <h1 className="text-6xl font-display font-light mb-6 tracking-tighter">Authorized.</h1>
            <p className="text-xl text-white/50 mb-10 leading-relaxed font-light">
                Secure link established with <br/>
                <span className="text-white font-medium tracking-wider uppercase text-sm">{activeHouse.name}</span>
            </p>
            <button 
                onClick={() => setIsLoggedIn(false)}
                className="px-10 py-4 glass border border-white/20 rounded-2xl hover:bg-white hover:text-black transition-all duration-500 font-bold tracking-[0.2em] text-xs"
            >
                TERMINATE SESSION
            </button>
        </div>
      </div>
    );
  }

  return (
    <div className="relative min-h-screen w-full overflow-hidden bg-black">
      {/* Background Layer: Multi-image crossfade/slider */}
      <div className="absolute inset-0 z-0 overflow-hidden">
        {HOUSES.map((house, idx) => (
          <div
            key={house.id}
            className={`absolute inset-0 bg-transition ${
              idx === activeIndex 
                ? 'opacity-100 scale-100' 
                : 'opacity-0 scale-110'
            }`}
            style={{
              backgroundImage: `url(${house.imageUrl})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
            }}
          />
        ))}
        {/* Cinematic Filters */}
        <div className="absolute inset-0 bg-black/40 backdrop-blur-[2px]" />
        <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-black/60" />
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.4)_100%)]" />
      </div>

      {/* Main UI Layer */}
      <div className="relative z-10 h-screen flex flex-col">
        {/* Top Navbar */}
