                className={`w-full ${inputBg} border ${error ? 'border-red-500/50' : ''} rounded-xl px-4 py-3 ${inputTextColor} focus:outline-none focus:ring-1 focus:ring-emerald-500/30 transition-all duration-300 text-sm theme-transition`}
              />
