  const activeHouse = HOUSES[activeIndex];

  const handleNext = useCallback(() => {
    setActiveIndex((prev) => (prev + 1) % HOUSES.length);
  }, []);

  const handlePrev = useCallback(() => {
    setActiveIndex((prev) => (prev - 1 + HOUSES.length) % HOUSES.length);
  }, []);

  const toggleLoginTheme = () => {
    setLoginDarkMode((prev) => !prev);
  };

  const toggleDashboardTheme = () => {
    setDashboardDarkMode((prev) => !prev);
  };

  // Synchronize body class with the active view's theme state
  useEffect(() => {
    const currentDarkMode = isLoggedIn ? dashboardDarkMode : loginDarkMode;
    if (currentDarkMode) {
      document.body.classList.add('bg-black');
      document.body.classList.remove('bg-slate-50', 'bg-white');
      document.body.setAttribute('data-theme', 'dark');
    } else {
      document.body.classList.add(isLoggedIn ? 'bg-slate-50' : 'bg-white');
      document.body.classList.remove('bg-black');
      document.body.setAttribute('data-theme', 'light');
    }
  }, [isLoggedIn, loginDarkMode, dashboardDarkMode]);

  const handleLoginSuccess = (user: string) => {
    setUsername(user);
    setIsLoggedIn(true);
    // Optional: Initialize dashboard theme to match login theme on first entry
    setDashboardDarkMode(loginDarkMode);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUsername('');
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isLoggedIn) {
        if (e.key === 'ArrowRight') handleNext();
        if (e.key === 'ArrowLeft') handlePrev();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNext, handlePrev, isLoggedIn]);

  const textColor = loginDarkMode ? 'text-white' : 'text-slate-900';
  const navTextColor = loginDarkMode ? 'text-white/30 hover:text-white' : 'text-slate-400 hover:text-emerald-600';

  if (isLoggedIn) {
    return (
      <Dashboard 
        isDarkMode={dashboardDarkMode} 
        onToggleTheme={toggleDashboardTheme} 
        onLogout={handleLogout} 
      />
    );
  }

  return (
    <div className={`relative min-h-screen w-full overflow-hidden ${loginDarkMode ? 'bg-black' : 'bg-white'} transition-colors duration-500`}>
      {/* Background Slider */}
      <div className="absolute inset-0 z-0 overflow-hidden">
        {HOUSES.map((house, idx) => (
          <div
            key={house.id}
            className={`absolute inset-0 bg-transition ${
              idx === activeIndex 
                ? (loginDarkMode ? 'opacity-100 scale-100' : 'opacity-15 scale-100')
                : 'opacity-0 scale-110'
            }`}
            style={{
              backgroundImage: `url(${house.imageUrl})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
            }}
          />
        ))}
        {/* Visual Filters */}
        <div className={`absolute inset-0 ${loginDarkMode ? 'bg-black/50' : 'bg-white/70'} backdrop-blur-[1px] transition-all duration-500`} />
        <div className={`absolute inset-0 ${loginDarkMode ? 'bg-gradient-to-t from-black via-transparent to-black/60' : 'bg-gradient-to-t from-white via-transparent to-white/80'} transition-all duration-500`} />
        <div className={`absolute inset-0 ${loginDarkMode ? 'bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.5)_100%)]' : 'bg-[radial-gradient(circle_at_center,transparent_0%,rgba(255,255,255,0.4)_100%)]'} transition-all duration-500`} />
      </div>

      {/* Main UI */}
      <div className="relative z-10 h-screen flex flex-col">
        {/* Logo & Navigation */}
        <header className="px-8 py-10 md:px-16 flex justify-between items-center">
          <div className="flex items-center gap-4 group cursor-pointer">
            <div className={`w-8 h-8 flex items-center justify-center border ${loginDarkMode ? 'border-emerald-500/40 group-hover:border-emerald-400' : 'border-emerald-500/60 group-hover:border-emerald-600'} transition-all duration-500 theme-transition`}>
               <div className={`w-2 h-2 ${loginDarkMode ? 'bg-emerald-400' : 'bg-emerald-600'} animate-pulse theme-transition`} />
            </div>
            <span className={`${textColor} font-display text-lg font-bold tracking-[0.4em] uppercase opacity-80 group-hover:opacity-100 transition-opacity theme-transition`}>EduEase Energy</span>
          </div>

          <div className="flex items-center gap-12">
            <div className="hidden lg:flex gap-12">
              {['Infrastructures', 'Statistics', 'Emergency', 'Nodes'].map((link) => (
                <a key={link} href="#" className={`${navTextColor} transition-all text-[9px] font-bold uppercase tracking-[0.3em] theme-transition`}>{link}</a>
              ))}
            </div>

            <button 
              onClick={toggleLoginTheme}
              className={`p-2.5 rounded-xl border ${loginDarkMode ? 'border-white/10 bg-white/5 hover:bg-white/10 text-yellow-400' : 'border-slate-200 bg-slate-100 hover:bg-slate-200 text-slate-700'} shadow-sm transition-all duration-300`}
              aria-label={loginDarkMode ? "Switch to Light Mode" : "Switch to Dark Mode"}
            >
              {loginDarkMode ? (
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M10 2a1 1 0 011 1v1a1 1 0 11-2 0V3a1 1 0 011-1zm4 8a4 4 0 11-8 0 4 4 0 018 0zm-.464 4.95l.707.707a1 1 0 001.414-1.414l-.707-.707a1 1 0 00-1.414 1.414zm2.12-10.607a1 1 0 010 1.414l-.706.707a1 1 0 11-1.414-1.414l.707-.707a1 1 0 011.414 0zM17 11a1 1 0 100-2h-1a1 1 0 100 2h1zm-7 4a1 1 0 011 1v1a1 1 0 11-2 0v-1a1 1 0 011-1zM5.05 6.464A1 1 0 106.465 5.05l-.708-.707a1 1 0 00-1.414 1.414l.707.707zm1.414 8.486l-.707.707a1 1 0 01-1.414-1.414l.707-.707a1 1 0 011.414 1.414zM4 11a1 1 0 100-2H3a1 1 0 000 2h1z" clipRule="evenodd" />
                </svg>
              ) : (
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                  <path d="M17.293 13.293A8 8 0 016.707 2.707a8.001 8.001 0 1010.586 10.586z" />
                </svg>
              )}
            </button>
          </div>
        </header>

        {/* Horizontal Navigation */}
        <div className="absolute inset-y-0 left-0 w-32 flex items-center justify-center z-30">
            <button 
              onClick={handlePrev}
              className={`w-14 h-14 rounded-full border ${loginDarkMode ? 'border-white/5 bg-white/5 hover:bg-emerald-500 hover:text-black' : 'border-slate-200 bg-white/80 hover:bg-emerald-500 hover:text-white'} flex items-center justify-center transition-all duration-700 group -translate-x-4 hover:translate-x-0 ${loginDarkMode ? 'text-white' : 'text-slate-600'} shadow-lg`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M15 19l-7-7 7-7" />
              </svg>
            </button>
        </div>
        <div className="absolute inset-y-0 right-0 w-32 flex items-center justify-center z-30">
            <button 
              onClick={handleNext}
              className={`w-14 h-14 rounded-full border ${loginDarkMode ? 'border-white/5 bg-white/5 hover:bg-emerald-500 hover:text-black' : 'border-slate-200 bg-white/80 hover:bg-emerald-500 hover:text-white'} flex items-center justify-center transition-all duration-700 group translate-x-4 hover:translate-x-0 ${loginDarkMode ? 'text-white' : 'text-slate-600'} shadow-lg`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 5l7 7-7 7" />
              </svg>
            </button>
        </div>

        {/* Login Container */}
        <main className="flex-grow flex items-center justify-center px-4">
           <LoginForm 
              selectedHouseName={activeHouse.name} 
              onLogin={handleLoginSuccess}
              isDarkMode={loginDarkMode}
           />
        </main>

        {/* Dynamic Sector Information */}
        <footer className="px-8 pb-12 md:px-16 flex justify-between items-end">
          <div className="max-w-md overflow-hidden">
            <div key={activeHouse.id} className="animate-fade-in-up">
              <h3 className={`${loginDarkMode ? 'text-emerald-500/40' : 'text-emerald-600/60'} text-[8px] uppercase tracking-[0.4em] font-bold mb-1 theme-transition`}>FACILITY ID: {activeHouse.id}</h3>
              <p className={`${textColor} font-display text-3xl font-light tracking-tight mb-1 theme-transition`}>{activeHouse.name}</p>
              <p className={`${loginDarkMode ? 'text-white/40' : 'text-slate-500'} text-[10px] font-light tracking-[0.2em] uppercase italic theme-transition`}>{activeHouse.location}</p>
            </div>
          </div>

          <div className="flex flex-col items-end">
            <div className="flex gap-1.5 mb-3">
              {HOUSES.map((_, i) => (
                <div 
                  key={i} 
                  className={`h-[1px] transition-all duration-700 ${i === activeIndex ? (loginDarkMode ? 'w-12 bg-emerald-400' : 'w-12 bg-emerald-600') : (loginDarkMode ? 'w-3 bg-white/10' : 'w-3 bg-slate-300')}`}
                />
              ))}
            </div>
            <span className={`${loginDarkMode ? 'text-white/20' : 'text-slate-200'} font-display text-4xl font-extralight tracking-tighter theme-transition`}>
              {String(activeIndex + 1).padStart(2, '0')}
            </span>
          </div>
        </footer>
      </div>

      {/* Aesthetic Overlays */}
      <div className={`absolute inset-0 pointer-events-none ${loginDarkMode ? 'opacity-[0.05]' : 'opacity-[0.02]'} z-50 overflow-hidden theme-transition`}>
        <div className={`h-full w-full bg-[linear-gradient(transparent_0%,rgba(255,255,255,0.5)_50%,transparent_100%)] bg-[length:100%_8px]`} />
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';

interface LoginFormProps {
  onLogin: (username: string) => void;
  selectedHouseName: string;
  isDarkMode: boolean;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, selectedHouseName, isDarkMode }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    setTimeout(() => {
      if (username === 'Namyen' && password === '12345') {
        onLogin(username);
      } else {
        setError('Verification Failed');
        setIsLoading(false);
      }
    }, 1000);
  };

  const glassClass = isDarkMode ? 'glass-dark' : 'glass-light';
  const labelColor = isDarkMode ? 'text-white/40' : 'text-slate-500';
  const inputBg = isDarkMode ? 'bg-white/5 border-white/10' : 'bg-slate-50 border-slate-200';
  const inputTextColor = isDarkMode ? 'text-white placeholder-white/10' : 'text-slate-900 placeholder-slate-400';
  const headingColor = isDarkMode ? 'text-white' : 'text-slate-900';
  const subHeadingColor = isDarkMode ? 'text-white/60' : 'text-slate-600';

  return (
    <div className={`w-full max-w-[320px] mx-auto relative z-20 theme-transition ${error ? 'animate-shake' : ''}`}>
      <div className={`${glassClass} p-8 rounded-[2.5rem] relative overflow-hidden theme-transition`}>
        {/* Animated accent light */}
        <div className={`absolute -top-24 -right-24 w-48 h-48 ${isDarkMode ? 'bg-emerald-500/10' : 'bg-emerald-500/15'} blur-[80px] rounded-full pointer-events-none`} />

        <div className="relative z-10">
          <div className="mb-6 text-center">
            <h2 className={`text-2xl font-semibold ${headingColor} mb-1 tracking-tight font-display transition-colors`}>Welcome Back</h2>
            <p className={`${subHeadingColor} text-[10px] font-medium uppercase tracking-[0.15em] transition-colors`}>
              Node: <span className="text-emerald-500">{selectedHouseName}</span>
            </p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-1.5">
              <label className={`text-[9px] font-bold ${labelColor} uppercase tracking-[0.2em] ml-1`}>Identity</label>
              <input
                required
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="Username"
                className={`w-full ${inputBg} border rounded-2xl px-4 py-3 ${inputTextColor} focus:outline-none focus:ring-2 focus:ring-emerald-500/20 transition-all text-sm`}
              />
            </div>

            <div className="space-y-1.5">
              <label className={`text-[9px] font-bold ${labelColor} uppercase tracking-[0.2em] ml-1`}>Passkey</label>
              <input
                required
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className={`w-full ${inputBg} border rounded-2xl px-4 py-3 ${inputTextColor} focus:outline-none focus:ring-2 focus:ring-emerald-500/20 transition-all text-sm`}
              />
            </div>

            {error && (
              <p className="text-red-500 text-[10px] text-center font-bold tracking-wide">
                {error}
              </p>
            )}

            <button
              disabled={isLoading}
              type="submit"
              className="w-full bg-emerald-500 text-white font-bold py-3.5 rounded-2xl shadow-lg hover:bg-emerald-400 active:scale-[0.97] transition-all flex items-center justify-center gap-2 mt-2"
            >
              {isLoading ? (
                <div className="h-4 w-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <span className="tracking-widest text-[10px]">AUTHORIZE ACCESS</span>
              )}
            </button>

            <div className="text-center">
               <button type="button" className={`text-[9px] ${labelColor} hover:text-emerald-500 transition-colors tracking-tighter uppercase font-bold`}>
                 Secure Authentication Required
               </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

