  // Strictly separate theme states
  const [loginDarkMode, setLoginDarkMode] = useState(true);
  const [dashboardDarkMode, setDashboardDarkMode] = useState(false);
  const [hasLoggedInOnce, setHasLoggedInOnce] = useState(false);

  const activeHouse = HOUSES[activeIndex];

  const handleNext = useCallback(() => {
    setActiveIndex((prev) => (prev + 1) % HOUSES.length);
  }, []);

  const handlePrev = useCallback(() => {
    setActiveIndex((prev) => (prev - 1 + HOUSES.length) % HOUSES.length);
  }, []);

  const toggleLoginTheme = () => {
    setLoginDarkMode((prev) => !prev);
  };

  const toggleDashboardTheme = () => {
    setDashboardDarkMode((prev) => !prev);
  };

  // Synchronize global attributes with the current view's theme
  useEffect(() => {
    const currentDarkMode = isLoggedIn ? dashboardDarkMode : loginDarkMode;
    const body = document.body;

    if (currentDarkMode) {
      body.style.backgroundColor = '#000000';
      body.setAttribute('data-theme', 'dark');
    } else {
      body.style.backgroundColor = isLoggedIn ? '#f4f7fe' : '#ffffff';
      body.setAttribute('data-theme', 'light');
    }
  }, [isLoggedIn, loginDarkMode, dashboardDarkMode]);

  const handleLoginSuccess = (user: string) => {
    setUsername(user);
    setIsLoggedIn(true);

    // On the very first login, we can optionally inherit the theme
    if (!hasLoggedInOnce) {
      setDashboardDarkMode(loginDarkMode);
      setHasLoggedInOnce(true);
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUsername('');
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isLoggedIn) {
        if (e.key === 'ArrowRight') handleNext();
        if (e.key === 'ArrowLeft') handlePrev();
      }
