const dailyData = [
  { name: 'Mon', usage: 12.4 },
  { name: 'Tue', usage: 14.8 },
  { name: 'Wed', usage: 13.2 },
  { name: 'Thu', usage: 18.5 },
  { name: 'Fri', usage: 15.1 },
  { name: 'Sat', usage: 22.4 },
  { name: 'Sun', usage: 20.8 },
];

const monthlyData = [
  { name: 'Jul', usage: 420 },
  { name: 'Aug', usage: 380 },
  { name: 'Sep', usage: 450 },
  { name: 'Oct', usage: 520 },
  { name: 'Nov', usage: 480 },
  { name: 'Dec', usage: 610 },
];

interface DashboardProps {
    isDarkMode: boolean;
    onToggleTheme: () => void;
    onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ isDarkMode, onToggleTheme, onLogout }) => {
    const [currentPage, setCurrentPage] = useState('dashboard');
    const [lang, setLang] = useState<'th' | 'en'>('th');
    const [calcMode, setCalcMode] = useState<'hours' | 'budget'>('hours');
    const [statsFrame, setStatsFrame] = useState<'daily' | 'monthly'>('daily');

    // Calculator States
    const [watt, setWatt] = useState(1200);
    const [calcHr, setCalcHr] = useState(8);
    const [calcDay, setCalcDay] = useState(30);
    const [calcMoney, setCalcMoney] = useState(500);
    const RATE = 4.5;

    const t = (key: string) => (langData[lang] as any)[key] || key;

    const navItems = [
        { id: 'dashboard', icon: 'fas fa-home', key: 'm1' },
        { id: 'devices', icon: 'fas fa-plug', key: 'm2' },
        { id: 'calculator', icon: 'fas fa-calculator', key: 'm3' },
        { id: 'budget', icon: 'fas fa-wallet', key: 'm4' },
        { id: 'stats', icon: 'fas fa-chart-line', key: 'm5' },
        { id: 'noti', icon: 'fas fa-bell', key: 'm6' },
        { id: 'tips', icon: 'fas fa-lightbulb', key: 'm7' },
        { id: 'compare', icon: 'fas fa-balance-scale', key: 'm8' },
        { id: 'settings', icon: 'fas fa-cog', key: 'm9' },
    ];

    const currentChartData = useMemo(() => {
        return statsFrame === 'daily' ? dailyData : monthlyData;
    }, [statsFrame]);

    const calcResults = () => {
        if (calcMode === 'hours') {
            const units = (watt / 1000) * calcHr * calcDay;
            const cost = units * RATE;
            return {
                total: cost.toLocaleString(undefined, { minimumFractionDigits: 2 }),
                day: (units * RATE / calcDay || 0).toFixed(2),
                unit: units.toFixed(2)
            };
        } else {
            const totalHr = calcMoney / ((watt / 1000) * RATE);
            return {
                possibleHr: totalHr.toFixed(1),
                possibleDay: (totalHr / 8).toFixed(1)
            };
        }
    };

    const results = calcResults();

    const CustomTooltip = ({ active, payload, label }: TooltipProps<number, string>) => {
        if (active && payload && payload.length) {
            return (
                <div className="p-3 bg-white border border-light rounded shadow-sm">
                    <p className="mb-1 fw-bold text-dark">{label}</p>
                    <p className="mb-0 text-primary">
                        {payload[0].value} {statsFrame === 'daily' ? 'kWh' : 'kWh Total'}
                    </p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="dashboard-container" data-theme={isDarkMode ? 'dark' : 'light'}>
            <div className="sidebar flex flex-col justify-between">
                <div>
                  <h4 className="fw-bold text-primary mb-4 ps-2">EduEase Energy</h4>
                  <nav>
                      {navItems.map(item => (
                          <button 
                              key={item.id}
                              className={`nav-link ${currentPage === item.id ? 'active' : ''}`} 
                              onClick={() => setCurrentPage(item.id)}
                          >
                              <i className={item.icon}></i> <span>{t(item.key)}</span>
                          </button>
                      ))}
                  </nav>
                </div>

                <div className="pt-4 border-top border-secondary-subtle">
                  <button 
                    onClick={onLogout}
                    className="nav-link text-danger border-0 bg-transparent w-full text-start flex items-center gap-2 hover:bg-danger/10"
                  >
                    <i className="fas fa-sign-out-alt"></i> <span>{t('logout')}</span>
                  </button>
                </div>
            </div>

            <div className="main-content-dashboard">
                <div className="d-flex justify-content-between align-items-center mb-4">
                    <h4 className="fw-bold">{t(navItems.find(n => n.id === currentPage)?.key || 'm1')}</h4>
                    <div className="d-flex gap-2">
                        <button className="btn btn-light rounded-pill px-3 shadow-sm" onClick={() => setLang(lang === 'th' ? 'en' : 'th')}>
                            <i className="fas fa-globe me-2 text-primary"></i><span>{lang.toUpperCase()}</span>
                        </button>
                        <button className="btn btn-light rounded-circle shadow-sm" onClick={onToggleTheme}>
                            <i className={`fas ${isDarkMode ? 'fa-sun text-warning' : 'fa-moon text-primary'}`}></i>
                        </button>
                    </div>
                </div>

                {currentPage === 'dashboard' && (
                    <div className="page-content">
                        <div className="row g-3">
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db1')}</span><span className="val">฿ 1,250</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db2')}</span><span className="val text-success">{t('st_normal')}</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db3')}</span><span className="val">152 kWh</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db4')}</span><span className="val text-danger">15/01/2026</span></div></div>
                            <div className="col-12 mt-3"><div className="dashboard-card">
                                <h6 className="fw-bold mb-3">{t('quick')}</h6>
                                <div className="d-flex gap-2">
                                    <button className="btn btn-primary btn-sm px-4" onClick={() => setCurrentPage('devices')}><i className="fas fa-plug me-2"></i><span>{t('m2')}</span></button>
                                    <button className="btn btn-outline-primary btn-sm px-4" onClick={() => setCurrentPage('calculator')}><i className="fas fa-calculator me-2"></i><span>{t('m3')}</span></button>
                                </div>
                            </div></div>
                        </div>
                    </div>
                )}

                {currentPage === 'devices' && (
                    <div className="page-content">
                        <div className="row g-3">
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv1')}</span><span className="val">15 Items</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv2')}</span><span className="val text-primary pointer">+ Add New</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv3')}</span><span className="val">2,400W</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv4')}</span><span className="val">Kitchen: 45%</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv5')}</span><span className="val">AC: ฿850</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv6')}</span><span className="val">6.2 Hrs</span></div></div>
                            <div className="col-12"><div className="dashboard-card" style={{backgroundColor: 'rgba(111, 66, 193, 0.1)'}}>
                                <h6 className="fw-bold">{t('dv7')}</h6>
                                <p className="small mb-0 text-muted">{t('dv8')}</p>
                            </div></div>
                        </div>
                    </div>
                )}

                {currentPage === 'calculator' && (
                    <div className="page-content">
                        <div className="row g-4">
                            <div className="col-md-7">
                                <div className="dashboard-card border-0 shadow-sm">
                                    <div className="d-flex mb-4 gap-2">
                                        <button className={`btn btn-light w-50 btn-mode ${calcMode === 'hours' ? 'active' : ''}`} onClick={() => setCalcMode('hours')}><span>{t('c1')}</span></button>
                                        <button className={`btn btn-light w-50 btn-mode ${calcMode === 'budget' ? 'active' : ''}`} onClick={() => setCalcMode('budget')}><span>{t('c2')}</span></button>
                                    </div>
                                    <div className="mb-3"><label className="label mb-2">{t('c3')}</label>
                                        <select className="form-select" value={watt} onChange={(e) => setWatt(parseInt(e.target.value))}>
                                            <option value="1200">แอร์ (1,200W)</option><option value="150">ตู้เย็น (150W)</option><option value="100">ทีวี (100W)</option>
                                            <option value="50">พัดลม (50W)</option><option value="2000">เครื่องทำน้ำอุ่น (2,000W)</option><option value="0">ระบุเอง (Custom)</option>
                                        </select>
                                    </div>
                                    <div className="mb-4"><label className="label mb-2">{t('c4')}</label>
                                        <div className="d-flex align-items-center gap-3">
                                            <input type="range" className="form-range" min="10" max="4000" step="10" value={watt} onChange={(e) => setWatt(parseInt(e.target.value))} />
                                            <input type="number" className="form-control" style={{ width: '100px' }} value={watt} onChange={(e) => setWatt(parseInt(e.target.value))} />
                                        </div>
                                    </div>
                                    {calcMode === 'hours' ? (
                                        <div className="row">
                                            <div className="col-6"><label className="label">⏱️ ชม./วัน</label><input type="number" className="form-control" value={calcHr} onChange={(e) => setCalcHr(parseFloat(e.target.value))} /></div>
                                            <div className="col-6"><label className="label">📅 จำนวนวัน</label><input type="number" className="form-control" value={calcDay} onChange={(e) => setCalcDay(parseFloat(e.target.value))} /></div>
                                        </div>
                                    ) : (
                                        <div>
                                            <label className="label">💰 งบประมาณ (บาท)</label><input type="number" className="form-control" value={calcMoney} onChange={(e) => setCalcMoney(parseFloat(e.target.value))} />
                                        </div>
                                    )}
                                </div>
                            </div>
                            <div className="col-md-5">
                                <div className="dashboard-card h-100 bg-primary text-white border-0 shadow-lg">
                                    <h5 className="fw-bold mb-4">{t('c-res')}</h5>
                                    {calcMode === 'hours' ? (
                                        <div>
                                            <span className="label text-white-50">{t('c-total')}</span>
                                            <h1 className="fw-bold mt-1">฿ {results.total}</h1>
                                            <hr className="bg-white" /><div className="row">
                                                <div className="col-6"><small className="text-white-50">ต่อวัน</small><p className="fw-bold mb-0">฿ {results.day}</p></div>
                                                <div className="col-6"><small className="text-white-50">หน่วย (kWh)</small><p className="fw-bold mb-0">{results.unit}</p></div>
                                            </div>
                                        </div>
                                    ) : (
                                        <div>
                                            <span className="label text-white-50">ใช้งานได้นานประมาณ</span><h1 className="fw-bold mt-1">{results.possibleHr} ชม.</h1>
                                            <hr className="bg-white" /><small className="text-white-50">คิดเป็นจำนวนวัน (ใช้วันละ 8 ชม.)</small><h3 className="fw-bold">{results.possibleDay} วัน</h3>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {currentPage === 'budget' && (
                    <div className="page-content">
                        <div className="row g-3">
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('b1')}</span><span className="val">฿ 2,500</span></div></div>
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('b2')}</span><span className="val">Manage</span></div></div>
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('b3')}</span><span className="val text-warning">Used 70%</span></div></div>
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('b4')}</span><span className="val">70%, 90%, Over</span></div></div>
                            <div className="col-12"><button className="btn btn-outline-primary w-100">{t('b5')}</button></div>
                        </div>
                    </div>
                )}

                {currentPage === 'stats' && (
                    <div className="page-content">
                        <div className="row g-3 mb-4">
                            <div className="col-md-4">
                                <div 
                                    className={`sub-menu-box text-center ${statsFrame === 'daily' ? 'active' : ''}`}
                                    onClick={() => setStatsFrame('daily')}
                                >
                                    <i className="fas fa-calendar-day mb-2"></i><br/><span>{t('s1')}</span>
                                </div>
                            </div>
                            <div className="col-md-4">
                                <div 
                                    className={`sub-menu-box text-center ${statsFrame === 'monthly' ? 'active' : ''}`}
                                    onClick={() => setStatsFrame('monthly')}
                                >
                                    <i className="fas fa-calendar-alt mb-2"></i><br/><span>{t('s2')}</span>
                                </div>
                            </div>
                            <div className="col-md-4">
                                <div className="sub-menu-box text-center">
                                    <i className="fas fa-file-download mb-2"></i><br/><span>{t('s3')}</span>
                                </div>
                            </div>
                        </div>
                        <div className="row">
                            <div className="col-12">
                                <div className="dashboard-card p-4">
                                    <div className="d-flex justify-content-between align-items-center mb-4">
                                        <h6 className="fw-bold mb-0">{t('s4')} - {statsFrame === 'daily' ? t('s1') : t('s2')}</h6>
                                        <div className="badge bg-primary-subtle text-primary px-3 py-2 rounded-pill">
                                            {statsFrame === 'daily' ? 'Last 7 Days' : 'Last 6 Months'}
                                        </div>
                                    </div>
                                    <div style={{ width: '100%', height: '350px' }}>
                                        <ResponsiveContainer width="100%" height="100%">
                                            <AreaChart data={currentChartData}>
                                                <defs>
                                                    <linearGradient id="colorUsage" x1="0" y1="0" x2="0" y2="1">
                                                        <stop offset="5%" stopColor="var(--primary)" stopOpacity={0.3}/>
                                                        <stop offset="95%" stopColor="var(--primary)" stopOpacity={0}/>
                                                    </linearGradient>
                                                </defs>
                                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#1b254b' : '#eee'} />
                                                <XAxis 
                                                    dataKey="name" 
                                                    axisLine={false} 
                                                    tickLine={false} 
                                                    tick={{ fill: 'var(--text-gray)', fontSize: 12 }}
                                                />
                                                <YAxis 
                                                    axisLine={false} 
                                                    tickLine={false} 
                                                    tick={{ fill: 'var(--text-gray)', fontSize: 12 }}
                                                    unit={statsFrame === 'daily' ? ' kWh' : ' kWh'}
                                                />
                                                <Tooltip content={<CustomTooltip />} />
                                                <Area 
                                                    type="monotone" 
                                                    dataKey="usage" 
                                                    stroke="var(--primary)" 
                                                    strokeWidth={3}
                                                    fillOpacity={1} 
                                                    fill="url(#colorUsage)" 
                                                    animationDuration={1500}
                                                />
                                            </AreaChart>
                                        </ResponsiveContainer>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {currentPage === 'noti' && (
                    <div className="page-content">
                        <div className="row g-3">
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('n1')}</span><span className="val">5 New</span></div></div>
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('n2')}</span><span className="val text-danger">Alert!</span></div></div>
                            <div className="col-12"><div className="dashboard-card"><h6 className="fw-bold">{t('n3')}</h6>
                                <div className="form-check form-switch mt-3"><input className="form-check-input" type="checkbox" defaultChecked /><label className="ms-2">Budget Alerts</label></div>
                            </div></div>
                        </div>
                    </div>
                )}

                {currentPage === 'tips' && (
                    <div className="page-content">
                        <div className="row g-3">
                            <div className="col-md-6"><div className="dashboard-card border-start border-success border-5"><h6 className="fw-bold">{t('t1')}</h6><p className="small text-muted mb-0">ปิดไฟเมื่อไม่ใช้งาน...</p></div></div>
                            <div className="col-md-6"><div className="dashboard-card border-start border-primary border-5"><h6 className="fw-bold">{t('t2')}</h6><p className="small text-muted mb-0">ลดแอร์ช่วงบ่าย 2...</p></div></div>
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('t3')}</span><span className="val">Water Heater</span></div></div>
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('t4')}</span><span className="val">Energy Saver Badge</span></div></div>
                        </div>
                    </div>
                )}

                {currentPage === 'compare' && (
                    <div className="page-content">
                        <div className="row g-3">
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('cp1')}</span><span className="val text-success">-12%</span></div></div>
                            <div className="col-md-6"><div className="sub-menu-box"><span className="label">{t('cp2')}</span><span className="val">Normal</span></div></div>
                            <div className="col-12 text-center mt-4"><h5 className="fw-bold">{t('cp3')}</h5></div>
                        </div>
                    </div>
                )}

                {currentPage === 'settings' && (
                    <div className="page-content">
