                    <p className="mb-0 text-primary">
                        {payload[0].value} {statsFrame === 'daily' ? 'kWh' : 'kWh Total'}
                    </p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="dashboard-container" data-theme={isDarkMode ? 'dark' : 'light'}>
            <div className="sidebar flex flex-col justify-between">
                <div>
                  <h4 className="fw-bold text-primary mb-4 ps-2">EduEase Energy</h4>
                  <nav>
                      {navItems.map(item => (
                          <button 
                              key={item.id}
                              className={`nav-link ${currentPage === item.id ? 'active' : ''}`} 
                              onClick={() => setCurrentPage(item.id)}
                          >
                              <i className={item.icon}></i> <span>{t(item.key)}</span>
                          </button>
                      ))}
                  </nav>
                </div>

                <div className="pt-4 border-top border-secondary-subtle">
                  <button 
                    onClick={onLogout}
                    className="nav-link text-danger border-0 bg-transparent w-full text-start flex items-center gap-2 hover:bg-danger/10"
                  >
                    <i className="fas fa-sign-out-alt"></i> <span>{t('logout')}</span>
                  </button>
                </div>
