                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db2')}</span><span className="val text-success">{t('st_normal')}</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db3')}</span><span className="val">152 kWh</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db4')}</span><span className="val text-danger">15/01/2026</span></div></div>
                            <div className="col-12 mt-3"><div className="dashboard-card">
