    onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ isDarkMode, onToggleTheme, onLogout }) => {
    const [currentPage, setCurrentPage] = useState('dashboard');
    const [lang, setLang] = useState<'th' | 'en'>('th');
    const [calcMode, setCalcMode] = useState<'hours' | 'budget'>('hours');
    const [statsFrame, setStatsFrame] = useState<'daily' | 'monthly'>('daily');

    // Calculator States
    const [calcDay] = useState(30);
    const [calcMoney, setCalcMoney] = useState(500);
    const [multiDevices, setMultiDevices] = useState<MultiDeviceItem[]>([
        { id: Date.now(), name: 'Air Conditioner', watt: 1200, hours: 8 }
    ]);

    const RATE = 4.5;
    const t = (key: string) => (langData[lang] as any)[key] || key;

    const navItems = [
        { id: 'dashboard', icon: 'fas fa-home', key: 'm1' },
        { id: 'devices', icon: 'fas fa-plug', key: 'm2' },
        { id: 'calculator', icon: 'fas fa-calculator', key: 'm3' },
        { id: 'budget', icon: 'fas fa-wallet', key: 'm4' },
        { id: 'stats', icon: 'fas fa-chart-line', key: 'm5' },
        { id: 'noti', icon: 'fas fa-bell', key: 'm6' },
        { id: 'tips', icon: 'fas fa-lightbulb', key: 'm7' },
        { id: 'compare', icon: 'fas fa-balance-scale', key: 'm8' },
        { id: 'settings', icon: 'fas fa-cog', key: 'm9' },
    ];

    const currentChartData = useMemo(() => {
        return statsFrame === 'daily' ? dailyData : monthlyData;
    }, [statsFrame]);

    const addMultiDevice = () => {
        setMultiDevices([...multiDevices, { id: Date.now(), name: 'New Appliance', watt: 100, hours: 1 }]);
    };

    const removeMultiDevice = (id: number) => {
        if (multiDevices.length > 1) {
            setMultiDevices(multiDevices.filter(d => d.id !== id));
        }
    };

    const updateMultiDevice = (id: number, field: keyof MultiDeviceItem, value: any) => {
        setMultiDevices(multiDevices.map(d => d.id === id ? { ...d, [field]: value } : d));
    };

    const calcResults = () => {
        if (calcMode === 'hours') {
            let totalUnits = 0;
            multiDevices.forEach(d => {
                totalUnits += (d.watt / 1000) * d.hours * calcDay;
            });
            const cost = totalUnits * RATE;
            return {
                total: cost.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
                day: (cost / calcDay).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
                unit: totalUnits.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })
            };
        } else {
            // Budget mode uses the first device in list as the context
            const d = multiDevices[0];
            const totalHrPossible = calcMoney / ((d.watt / 1000) * RATE);
            return {
                possibleHr: totalHrPossible.toFixed(1),
                possibleDay: (totalHrPossible / 8).toFixed(1)
            };
        }
    };

    const results = calcResults();

    const CustomTooltip = ({ active, payload, label }: TooltipProps<number, string>) => {
        if (active && payload && payload.length) {
            return (
                <div className="p-3 bg-white border border-light rounded shadow-sm">
                    <p className="mb-1 fw-bold text-dark">{label}</p>
                    <p className="mb-0 text-primary">
                        {payload[0].value} {statsFrame === 'daily' ? 'kWh' : 'kWh Total'}
                    </p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="dashboard-container" data-theme={isDarkMode ? 'dark' : 'light'}>
            <div className="sidebar flex flex-col justify-between">
                <div>
                  <h4 className="fw-bold text-primary mb-4 ps-2">EduEase Energy</h4>
                  <nav>
                      {navItems.map(item => (
                          <button 
                              key={item.id}
                              className={`nav-link ${currentPage === item.id ? 'active' : ''}`} 
                              onClick={() => setCurrentPage(item.id)}
                          >
                              <i className={item.icon}></i> <span>{t(item.key)}</span>
                          </button>
                      ))}
                  </nav>
                </div>

                <div className="pt-4 border-top border-secondary-subtle">
                  <button 
                    onClick={onLogout}
                    className="nav-link text-danger border-0 bg-transparent w-full text-start flex items-center gap-2 hover:bg-danger/10"
                  >
                    <i className="fas fa-sign-out-alt"></i> <span>{t('logout')}</span>
                  </button>
                </div>
            </div>

            <div className="main-content-dashboard">
                <div className="d-flex justify-content-between align-items-center mb-4">
                    <h4 className="fw-bold">{t(navItems.find(n => n.id === currentPage)?.key || 'm1')}</h4>
                    <div className="d-flex gap-2">
                        <button className="btn btn-light rounded-pill px-3 shadow-sm" onClick={() => setLang(lang === 'th' ? 'en' : 'th')}>
                            <i className="fas fa-globe me-2 text-primary"></i><span>{lang.toUpperCase()}</span>
                        </button>
                        <button className="btn btn-light rounded-circle shadow-sm" onClick={onToggleTheme}>
                            <i className={`fas ${isDarkMode ? 'fa-sun text-warning' : 'fa-moon text-primary'}`}></i>
                        </button>
                    </div>
                </div>

                {currentPage === 'dashboard' && (
                    <div className="page-content">
                        <div className="row g-3">
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db1')}</span><span className="val">฿ 1,250</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db2')}</span><span className="val text-success">{t('st_normal')}</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db3')}</span><span className="val">152 kWh</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db4')}</span><span className="val text-danger">15/01/2026</span></div></div>
                            <div className="col-12 mt-3"><div className="dashboard-card">
                                <h6 className="fw-bold mb-3">{t('quick')}</h6>
                                <div className="d-flex gap-2">
                                    <button className="btn btn-primary btn-sm px-4" onClick={() => setCurrentPage('devices')}><i className="fas fa-plug me-2"></i><span>{t('m2')}</span></button>
                                    <button className="btn btn-outline-primary btn-sm px-4" onClick={() => setCurrentPage('calculator')}><i className="fas fa-calculator me-2"></i><span>{t('m3')}</span></button>
                                </div>
                            </div></div>
                        </div>
                    </div>
                )}

                {currentPage === 'calculator' && (
                    <div className="page-content">
                        <div className="row g-4">
                            <div className="col-xl-8">
                                <div className="dashboard-card border-0 shadow-sm p-4">
                                    <div className="d-flex mb-4 gap-2">
                                        <button className={`btn btn-light w-50 btn-mode ${calcMode === 'hours' ? 'active' : ''}`} onClick={() => setCalcMode('hours')}><span>{t('c1')}</span></button>
                                        <button className={`btn btn-light w-50 btn-mode ${calcMode === 'budget' ? 'active' : ''}`} onClick={() => setCalcMode('budget')}><span>{t('c2')}</span></button>
                                    </div>

                                    {calcMode === 'hours' ? (
                                        <div className="multi-device-section">
                                            <div className="device-list space-y-4">
                                                {multiDevices.map((device, idx) => (
                                                    <div key={device.id} className="p-3 border border-secondary-subtle rounded-4 bg-light/5">
                                                        <div className="row g-3 align-items-end">
                                                            <div className="col-md-4">
                                                                <label className="label mb-2">{t('c_device_name')}</label>
                                                                <select 
                                                                    className="form-select" 
                                                                    value={PRESETS.find(p => p.watt === device.watt)?.name || 'Custom'}
                                                                    onChange={(e) => {
                                                                        const p = PRESETS.find(preset => preset.name === e.target.value);
                                                                        if(p) {
                                                                            updateMultiDevice(device.id, 'name', p.name);
                                                                            updateMultiDevice(device.id, 'watt', p.watt);
                                                                        }
                                                                    }}
                                                                >
                                                                    {PRESETS.map(p => <option key={p.name} value={p.name}>{p.name} ({p.watt}W)</option>)}
                                                                    <option value="Custom">Custom / ระบุเอง</option>
                                                                </select>
                                                            </div>
                                                            <div className="col-md-3">
                                                                <label className="label mb-2">{t('c_watts')}</label>
                                                                <input 
                                                                    type="number" 
                                                                    className="form-control" 
                                                                    value={device.watt}
                                                                    onChange={(e) => updateMultiDevice(device.id, 'watt', parseInt(e.target.value) || 0)}
                                                                />
                                                            </div>
                                                            <div className="col-md-3">
                                                                <label className="label mb-2">{t('c_hours')}</label>
                                                                <input 
                                                                    type="number" 
                                                                    className="form-control" 
                                                                    value={device.hours}
                                                                    step="0.5"
                                                                    onChange={(e) => updateMultiDevice(device.id, 'hours', parseFloat(e.target.value) || 0)}
                                                                />
                                                            </div>
                                                            <div className="col-md-2 text-end">
                                                                <button 
                                                                    className="btn btn-outline-danger btn-sm w-100 py-2 rounded-3"
                                                                    onClick={() => removeMultiDevice(device.id)}
                                                                    disabled={multiDevices.length === 1}
                                                                >
                                                                    <i className="fas fa-trash-alt"></i>
                                                                </button>
                                                            </div>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                            <button 
                                                className="btn btn-outline-primary w-100 mt-4 py-3 rounded-4 fw-bold"
                                                onClick={addMultiDevice}
                                            >
                                                <i className="fas fa-plus-circle me-2"></i> {t('c_add')}
                                            </button>
                                        </div>
                                    ) : (
                                        <div className="budget-mode-section">
                                            <div className="mb-4">
                                                <label className="label mb-2">{t('c3')}</label>
                                                <select className="form-select" value={multiDevices[0].watt} onChange={(e) => updateMultiDevice(multiDevices[0].id, 'watt', parseInt(e.target.value))}>
                                                    {PRESETS.map(p => <option key={p.name} value={p.watt}>{p.name} ({p.watt}W)</option>)}
                                                </select>
                                            </div>
                                            <div className="mb-4">
                                                <label className="label mb-2">💰 {t('c2')} (บาท)</label>
                                                <input 
                                                    type="number" 
                                                    className="form-control form-control-lg" 
                                                    value={calcMoney} 
                                                    onChange={(e) => setCalcMoney(parseFloat(e.target.value))} 
                                                />
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </div>

                            <div className="col-xl-4">
                                <div className="dashboard-card h-100 bg-primary text-white border-0 shadow-lg p-5 flex flex-col justify-center">
                                    <h5 className="fw-bold mb-4 opacity-80">{t('c-res')}</h5>
                                    {calcMode === 'hours' ? (
                                        <div className="animate-fade-in">
                                            <span className="label text-white-50">{t('c-total')}</span>
                                            <h1 className="fw-bold mt-2 text-5xl tracking-tight">฿ {results.total}</h1>
                                            <div className="my-4 border-top border-white opacity-20"></div>
                                            <div className="row g-4">
                                                <div className="col-6">
                                                    <small className="text-white-50 uppercase text-[10px] fw-bold block mb-1">เฉลี่ยต่อวัน</small>
                                                    <p className="fw-bold text-xl mb-0">฿ {results.day}</p>
                                                </div>
                                                <div className="col-6">
                                                    <small className="text-white-50 uppercase text-[10px] fw-bold block mb-1">หน่วย (kWh)</small>
                                                    <p className="fw-bold text-xl mb-0">{results.unit}</p>
                                                </div>
                                            </div>
                                            <p className="small mt-5 text-white-50 italic opacity-60">
                                                * ค่าไฟฟ้าฐานประมาณ 4.5 บาท/หน่วย <br/> 
                                                รวม {multiDevices.length} อุปกรณ์
                                            </p>
                                        </div>
                                    ) : (
                                        <div className="animate-fade-in text-center py-4">
                                            <span className="label text-white-50">คุณสามารถใช้งานอุปกรณ์นี้ได้</span>
                                            <h1 className="fw-bold mt-2 text-6xl tracking-tighter">{results.possibleHr} <small className="text-2xl">ชม.</small></h1>
                                            <div className="my-4 border-top border-white opacity-20"></div>
                                            <small className="text-white-50 block mb-2">คิดเป็นจำนวนวัน (กรณีใช้งานเฉลี่ย 8 ชม./วัน)</small>
                                            <h2 className="fw-bold text-3xl">{results.possibleDay} วัน</h2>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {currentPage === 'devices' && (
                    <div className="page-content">
                        <div className="row g-3">
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv1')}</span><span className="val">15 Items</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv2')}</span><span className="val text-primary pointer">+ Add New</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv3')}</span><span className="val">2,400W</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv4')}</span><span className="val">Kitchen: 45%</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv5')}</span><span className="val">AC: ฿850</span></div></div>
                            <div className="col-md-4"><div className="sub-menu-box"><span className="label">{t('dv6')}</span><span className="val">6.2 Hrs</span></div></div>
                            <div className="col-12"><div className="dashboard-card" style={{backgroundColor: 'rgba(111, 66, 193, 0.1)'}}>
                                <h6 className="fw-bold">{t('dv7')}</h6>
                                <p className="small mb-0 text-muted">{t('dv8')}</p>
                            </div></div>
                        </div>
                    </div>
                )}

                {currentPage === 'stats' && (
                    <div className="page-content">
                        <div className="row g-3 mb-4">
                            <div className="col-md-4">
                                <div 
                                    className={`sub-menu-box text-center ${statsFrame === 'daily' ? 'active' : ''}`}
                                    onClick={() => setStatsFrame('daily')}
                                >
                                    <i className="fas fa-calendar-day mb-2"></i><br/><span>{t('s1')}</span>
                                </div>
                            </div>
                            <div className="col-md-4">
                                <div 
                                    className={`sub-menu-box text-center ${statsFrame === 'monthly' ? 'active' : ''}`}
                                    onClick={() => setStatsFrame('monthly')}
                                >
                                    <i className="fas fa-calendar-alt mb-2"></i><br/><span>{t('s2')}</span>
                                </div>
                            </div>
                            <div className="col-md-4">
                                <div className="sub-menu-box text-center">
                                    <i className="fas fa-file-download mb-2"></i><br/><span>{t('s3')}</span>
                                </div>
                            </div>
                        </div>
                        <div className="row">
                            <div className="col-12">
                                <div className="dashboard-card p-4">
                                    <div className="d-flex justify-content-between align-items-center mb-4">
                                        <h6 className="fw-bold mb-0">{t('s4')} - {statsFrame === 'daily' ? t('s1') : t('s2')}</h6>
                                        <div className="badge bg-primary-subtle text-primary px-3 py-2 rounded-pill">
                                            {statsFrame === 'daily' ? 'Last 7 Days' : 'Last 6 Months'}
                                        </div>
                                    </div>
                                    <div style={{ width: '100%', height: '350px' }}>
                                        <ResponsiveContainer width="100%" height="100%">
                                            <AreaChart data={currentChartData}>
                                                <defs>
                                                    <linearGradient id="colorUsage" x1="0" y1="0" x2="0" y2="1">
                                                        <stop offset="5%" stopColor="var(--primary)" stopOpacity={0.3}/>
                                                        <stop offset="95%" stopColor="var(--primary)" stopOpacity={0}/>
                                                    </linearGradient>
                                                </defs>
                                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#1b254b' : '#eee'} />
                                                <XAxis 
                                                    dataKey="name" 
                                                    axisLine={false} 
                                                    tickLine={false} 
                                                    tick={{ fill: 'var(--text-gray)', fontSize: 12 }}
                                                />
                                                <YAxis 
                                                    axisLine={false} 
                                                    tickLine={false} 
                                                    tick={{ fill: 'var(--text-gray)', fontSize: 12 }}
                                                    unit={statsFrame === 'daily' ? ' kWh' : ' kWh'}
                                                />
                                                <Tooltip content={<CustomTooltip />} />
                                                <Area 
                                                    type="monotone" 
                                                    dataKey="usage" 
                                                    stroke="var(--primary)" 
                                                    strokeWidth={3}
                                                    fillOpacity={1} 
                                                    fill="url(#colorUsage)" 
                                                    animationDuration={1500}
                                                />
                                            </AreaChart>
                                        </ResponsiveContainer>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Other screens remain as placeholder templates */}
                {['budget', 'noti', 'tips', 'compare', 'settings'].includes(currentPage) && (
                    <div className="page-content animate-fade-in">
                        <div className="dashboard-card text-center py-5">
                            <i className={`${navItems.find(n => n.id === currentPage)?.icon} text-primary-subtle text-8xl mb-4`}></i>
                            <h5 className="fw-bold">{t(navItems.find(n => n.id === currentPage)?.key || '')}</h5>
                            <p className="text-muted">Section functionality coming soon in next version.</p>
                            {currentPage === 'settings' && (
                                <button className="btn btn-danger px-5 py-2 mt-3 rounded-pill" onClick={onLogout}>
                                    <i className="fas fa-sign-out-alt me-2"></i> {t('logout')}
                                </button>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Dashboard;

