const PRESETS = [
    { name: 'Air Conditioner', watt: 1200 },
    { name: 'Refrigerator', watt: 150 },
    { name: 'LED TV', watt: 100 },
    { name: 'Electric Fan', watt: 50 },
    { name: 'Water Heater', watt: 2000 },
    { name: 'Microwave', watt: 800 },
    { name: 'Laptop', watt: 65 },
];

const dailyData = [
  { name: 'Mon', usage: 12.4 }, { name: 'Tue', usage: 14.8 }, { name: 'Wed', usage: 13.2 },
  { name: 'Thu', usage: 18.5 }, { name: 'Fri', usage: 15.1 }, { name: 'Sat', usage: 22.4 },
  { name: 'Sun', usage: 20.8 },
];

const monthlyData = [
  { name: 'Jul', usage: 420 }, { name: 'Aug', usage: 380 }, { name: 'Sep', usage: 450 },
  { name: 'Oct', usage: 520 }, { name: 'Nov', usage: 480 }, { name: 'Dec', usage: 610 },
];

interface MultiDeviceItem {
    id: number;
    name: string;
    watt: number;
    hours: number;
}

interface DashboardProps {
    isDarkMode: boolean;
    onToggleTheme: () => void;
    onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ isDarkMode, onToggleTheme, onLogout }) => {
    const [currentPage, setCurrentPage] = useState('dashboard');
    const [lang, setLang] = useState<'th' | 'en'>('th');
    const [calcMode, setCalcMode] = useState<'hours' | 'budget'>('hours');
    const [statsFrame, setStatsFrame] = useState<'daily' | 'monthly'>('daily');

    // Calculator Configuration
    const [calcDays, setCalcDays] = useState(30);
    const [unitRate, setUnitRate] = useState(4.5);
    const [calcMoney, setCalcMoney] = useState(500);
    const [multiDevices, setMultiDevices] = useState<MultiDeviceItem[]>([
        { id: Date.now(), name: 'Air Conditioner', watt: 1200, hours: 8 }
    ]);

    const t = (key: string) => (langData[lang] as any)[key] || key;

    const navItems = [
        { id: 'dashboard', icon: 'fas fa-home', key: 'm1' },
        { id: 'devices', icon: 'fas fa-plug', key: 'm2' },
        { id: 'calculator', icon: 'fas fa-calculator', key: 'm3' },
        { id: 'budget', icon: 'fas fa-wallet', key: 'm4' },
        { id: 'stats', icon: 'fas fa-chart-line', key: 'm5' },
        { id: 'noti', icon: 'fas fa-bell', key: 'm6' },
        { id: 'tips', icon: 'fas fa-lightbulb', key: 'm7' },
        { id: 'compare', icon: 'fas fa-balance-scale', key: 'm8' },
        { id: 'settings', icon: 'fas fa-cog', key: 'm9' },
    ];

    const currentChartData = useMemo(() => statsFrame === 'daily' ? dailyData : monthlyData, [statsFrame]);

    const addMultiDevice = () => {
        setMultiDevices([...multiDevices, { id: Date.now(), name: 'New Appliance', watt: 100, hours: 1 }]);
    };

    const removeMultiDevice = (id: number) => {
        if (multiDevices.length > 1) {
            setMultiDevices(multiDevices.filter(d => d.id !== id));
        }
    };

    const updateMultiDevice = (id: number, field: keyof MultiDeviceItem, value: any) => {
        setMultiDevices(multiDevices.map(d => d.id === id ? { ...d, [field]: value } : d));
    };

    const getDeviceResults = (device: MultiDeviceItem) => {
        const units = (device.watt / 1000) * device.hours * calcDays;
        const cost = units * unitRate;
        return {
            cost: cost.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
            units: units.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
            dailyCost: (cost / calcDays).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })
        };
    };

    const grandTotal = useMemo(() => {
        let totalUnits = 0;
        multiDevices.forEach(d => {
            totalUnits += (d.watt / 1000) * d.hours * calcDays;
        });
        const cost = totalUnits * unitRate;
        return {
            totalCost: cost.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
            totalUnits: totalUnits.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
            avgDaily: (cost / calcDays).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })
        };
    }, [multiDevices, calcDays, unitRate]);

    const budgetResults = useMemo(() => {
        const d = multiDevices[0];
        const totalHrPossible = calcMoney / ((d.watt / 1000) * unitRate);
        return {
            possibleHr: totalHrPossible.toFixed(1),
            possibleDay: (totalHrPossible / 8).toFixed(1)
        };
    }, [multiDevices, calcMoney, unitRate]);

    const CustomTooltip = ({ active, payload, label }: TooltipProps<number, string>) => {
        if (active && payload && payload.length) {
            return (
                <div className="p-3 bg-white border border-light rounded shadow-sm">
                    <p className="mb-1 fw-bold text-dark">{label}</p>
                    <p className="mb-0 text-primary">{payload[0].value} {statsFrame === 'daily' ? 'kWh' : 'kWh Total'}</p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="dashboard-container" data-theme={isDarkMode ? 'dark' : 'light'}>
            <div className="sidebar flex flex-col justify-between">
                <div>
                    <h4 className="fw-bold text-primary mb-4 ps-2">EduEase Energy</h4>
                    <nav>
                        {navItems.map(item => (
                            <button key={item.id} className={`nav-link ${currentPage === item.id ? 'active' : ''}`} onClick={() => setCurrentPage(item.id)}>
                                <i className={item.icon}></i> <span>{t(item.key)}</span>
                            </button>
                        ))}
                    </nav>
                </div>
                <div className="pt-4 border-top border-secondary-subtle">
                    <button onClick={onLogout} className="nav-link text-danger border-0 bg-transparent w-full text-start flex items-center gap-2 hover:bg-danger/10">
                        <i className="fas fa-sign-out-alt"></i> <span>{t('logout')}</span>
                    </button>
                </div>
            </div>

            <div className="main-content-dashboard">
                <div className="d-flex justify-content-between align-items-center mb-4">
                    <h4 className="fw-bold">{t(navItems.find(n => n.id === currentPage)?.key || 'm1')}</h4>
                    <div className="d-flex gap-2">
                        <button className="btn btn-light rounded-pill px-3 shadow-sm" onClick={() => setLang(lang === 'th' ? 'en' : 'th')}>
                            <i className="fas fa-globe me-2 text-primary"></i><span>{lang.toUpperCase()}</span>
                        </button>
                        <button className="btn btn-light rounded-circle shadow-sm" onClick={onToggleTheme}>
                            <i className={`fas ${isDarkMode ? 'fa-sun text-warning' : 'fa-moon text-primary'}`}></i>
                        </button>
                    </div>
                </div>

                {currentPage === 'dashboard' && (
                    <div className="page-content animate-fade-in">
                        <div className="row g-3">
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db1')}</span><span className="val">฿ 1,250</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db2')}</span><span className="val text-success">{t('st_normal')}</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db3')}</span><span className="val">152 kWh</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card"><span className="label">{t('db4')}</span><span className="val text-danger">15/01/2026</span></div></div>
                        </div>
                    </div>
                )}

                {currentPage === 'calculator' && (
                    <div className="page-content animate-fade-in">
                        {/* Global Config Card */}
                        <div className="dashboard-card border-0 shadow-sm mb-4 p-4">
                            <div className="row g-4 align-items-center">
                                <div className="col-md-4">
                                    <label className="label mb-2"><i className="fas fa-bolt me-2"></i>{t('c_rate')}</label>
                                    <input type="number" step="0.1" className="form-control form-control-lg fw-bold" value={unitRate} onChange={(e) => setUnitRate(parseFloat(e.target.value) || 0)} />
                                </div>
                                <div className="col-md-4">
                                    <label className="label mb-2"><i className="fas fa-calendar-alt me-2"></i>{t('c_days')}</label>
                                    <input type="number" className="form-control form-control-lg fw-bold" value={calcDays} onChange={(e) => setCalcDays(parseInt(e.target.value) || 0)} />
                                </div>
                                <div className="col-md-4 d-flex gap-2 pt-2">
                                    <button className={`btn w-50 py-3 rounded-4 fw-bold ${calcMode === 'hours' ? 'btn-primary' : 'btn-light'}`} onClick={() => setCalcMode('hours')}>{t('c1')}</button>
                                    <button className={`btn w-50 py-3 rounded-4 fw-bold ${calcMode === 'budget' ? 'btn-primary' : 'btn-light'}`} onClick={() => setCalcMode('budget')}>{t('c2')}</button>
                                </div>
                            </div>
                        </div>

                        <div className="row g-4">
                            <div className="col-xl-8">
                                <div className="space-y-4">
                                    {calcMode === 'hours' ? (
                                        multiDevices.map((device) => {
                                            const devResults = getDeviceResults(device);
                                            return (
                                                <div key={device.id} className="dashboard-card border-0 shadow-sm p-4 hover:shadow-md transition-shadow">
                                                    <div className="row g-3">
                                                        <div className="col-lg-7">
                                                            <div className="row g-3">
                                                                <div className="col-12">
                                                                    <label className="label mb-2">{t('c_device_name')}</label>
                                                                    <div className="d-flex gap-2">
                                                                        <select 
                                                                            className="form-select flex-grow-1"
                                                                            value={PRESETS.find(p => p.watt === device.watt)?.name || 'Custom'}
                                                                            onChange={(e) => {
                                                                                const p = PRESETS.find(preset => preset.name === e.target.value);
                                                                                if(p) { updateMultiDevice(device.id, 'name', p.name); updateMultiDevice(device.id, 'watt', p.watt); }
                                                                            }}
                                                                        >
                                                                            {PRESETS.map(p => <option key={p.name} value={p.name}>{p.name}</option>)}
                                                                            <option value="Custom">Custom / อื่นๆ</option>
                                                                        </select>
                                                                        <button className="btn btn-outline-danger px-3 rounded-3" onClick={() => removeMultiDevice(device.id)} disabled={multiDevices.length === 1}><i className="fas fa-trash-alt"></i></button>
                                                                    </div>
                                                                </div>
                                                                <div className="col-6">
                                                                    <label className="label mb-2">{t('c_watts')}</label>
                                                                    <input type="number" className="form-control" value={device.watt} onChange={(e) => updateMultiDevice(device.id, 'watt', parseInt(e.target.value) || 0)} />
                                                                </div>
                                                                <div className="col-6">
                                                                    <label className="label mb-2">{t('c_hours')}</label>
                                                                    <input type="number" step="0.5" className="form-control" value={device.hours} onChange={(e) => updateMultiDevice(device.id, 'hours', parseFloat(e.target.value) || 0)} />
                                                                </div>
                                                            </div>
                                                        </div>
                                                        <div className="col-lg-5 border-start ps-lg-4 d-flex flex-column justify-content-center">
                                                            <div className="text-end">
                                                                <span className="label text-primary">{t('c-total')} (ชิ้นนี้)</span>
                                                                <h2 className="fw-bold text-primary text-4xl mb-3">฿ {devResults.cost}</h2>
                                                                <div className="row g-2">
                                                                    <div className="col-6">
                                                                        <small className="label block text-[11px]">หน่วยใช้ไป</small>
                                                                        <span className="fw-bold text-xl">{devResults.units} kWh</span>
                                                                    </div>
                                                                    <div className="col-6">
                                                                        <small className="label block text-[11px]">เฉลี่ยต่อวัน</small>
                                                                        <span className="fw-bold text-xl">฿ {devResults.dailyCost}</span>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            );
                                        })
                                    ) : (
                                        <div className="dashboard-card border-0 shadow-sm p-5 text-center">
                                            <div className="max-w-md mx-auto">
                                                <i className="fas fa-wallet text-primary text-6xl mb-4"></i>
                                                <h4 className="fw-bold mb-4">คำนวณจากงบประมาณ</h4>
                                                <div className="mb-4 text-start">
                                                    <label className="label mb-2">ระบุงบประมาณ (บาท)</label>
                                                    <input type="number" className="form-control form-control-lg text-center fw-bold" value={calcMoney} onChange={(e) => setCalcMoney(parseFloat(e.target.value) || 0)} />
                                                </div>
                                                <div className="text-start">
                                                    <label className="label mb-2">เลือกอุปกรณ์หลัก</label>
                                                    <select className="form-select form-select-lg" value={multiDevices[0].watt} onChange={(e) => updateMultiDevice(multiDevices[0].id, 'watt', parseInt(e.target.value))}>
                                                        {PRESETS.map(p => <option key={p.name} value={p.watt}>{p.name} ({p.watt}W)</option>)}
                                                    </select>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                    {calcMode === 'hours' && (
                                        <button className="btn btn-outline-primary w-100 py-3 rounded-4 fw-bold shadow-sm" onClick={addMultiDevice}>
                                            <i className="fas fa-plus-circle me-2"></i> {t('c_add')}
                                        </button>
                                    )}
                                </div>
                            </div>

                            <div className="col-xl-4">
                                <div className="dashboard-card h-100 bg-primary text-white border-0 shadow-lg p-5 sticky-top" style={{ top: '20px' }}>
                                    <h5 className="fw-bold mb-5 opacity-80 border-bottom border-white/20 pb-3">{t('c-res')}</h5>
                                    {calcMode === 'hours' ? (
                                        <div className="animate-fade-in">
                                            <span className="label text-white-50 block mb-1">{t('c-total')}</span>
                                            <h1 className="fw-bold text-6xl tracking-tight mb-5">฿ {grandTotal.totalCost}</h1>

                                            <div className="space-y-6">
                                                <div className="p-4 rounded-4 bg-white/10 backdrop-blur-sm border border-white/5">
                                                    <span className="label text-white-50 block text-xs uppercase tracking-widest mb-2">การใช้ไฟรวมทั้งหมด</span>
                                                    <h3 className="fw-bold text-4xl">{grandTotal.totalUnits} <small className="text-xl">kWh</small></h3>
                                                </div>

                                                <div className="p-4 rounded-4 bg-white/10 backdrop-blur-sm border border-white/5">
                                                    <span className="label text-white-50 block text-xs uppercase tracking-widest mb-2">เฉลี่ยต่อวันรวม</span>
                                                    <h3 className="fw-bold text-4xl">฿ {grandTotal.avgDaily}</h3>
                                                </div>
                                            </div>

                                            <div className="mt-5 p-3 rounded-3 bg-yellow-400/10 border border-yellow-400/20 text-yellow-100 text-[12px] italic">
                                                <i className="fas fa-info-circle me-2"></i>
                                                รวมการคำนวณจาก {multiDevices.length} อุปกรณ์ เป็นเวลา {calcDays} วัน 
                                                โดยใช้อัตราค่าไฟ {unitRate} บาท/หน่วย
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="animate-fade-in text-center py-4">
                                            <span className="label text-white-50 text-lg">คุณสามารถใช้งานอุปกรณ์นี้ได้</span>
                                            <h1 className="fw-bold mt-3 text-7xl tracking-tighter">{budgetResults.possibleHr} <small className="text-2xl">ชม.</small></h1>
                                            <div className="my-5 border-top border-white opacity-20"></div>
                                            <small className="text-white-50 block text-sm mb-2">คิดเป็นจำนวนวัน (กรณีใช้งาน 8 ชม./วัน)</small>
                                            <h2 className="fw-bold text-5xl">{budgetResults.possibleDay} วัน</h2>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Placeholders for other sections */}
                {['devices', 'stats', 'budget', 'noti', 'tips', 'compare', 'settings'].includes(currentPage) && (
                    <div className="page-content animate-fade-in">
                        <div className="dashboard-card text-center py-5">
                            <i className={`${navItems.find(n => n.id === currentPage)?.icon} text-primary-subtle text-8xl mb-4`}></i>
                            <h5 className="fw-bold">{t(navItems.find(n => n.id === currentPage)?.key || '')}</h5>
                            <p className="text-muted">Coming soon in next module update.</p>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Dashboard;

