        c_add: "Add Appliance", c_device_name: "Device Name", c_watts: "Watts", c_hours: "Hrs/Day",
        c_rate: "Rate per Unit (THB)", c_days: "Calculation Days", c_manual: "Manual Billing System",
        b1: "🏠 Home Budget", b2: "🔌 Device Budget", b3: "📉 Budget Status", b4: "🔔 Budget Alerts", b5: "✏️ Edit Budget",
        s1: "Daily Stats", s2: "Monthly Stats", s3: "Download PDF/CSV", s4: "📈 Usage Trend",
        n1: "📬 All Noti", n2: "⚠️ High Usage", n3: "⚙️ Noti Settings",
        t1: "🌱 Energy Saving Tips", t2: "🤖 AI Suggestions", t3: "🔍 High Load Analysis", t4: "🏆 Achievement",
        cp1: "📊 Area Average", cp2: "🏠 Size Comparison", cp3: "Energy Level: Low",
        st1: "👤 Profile", st2: "🌐 Language", st4: "Dark Mode", st7: "Logout",
        logout: "Sign Out"
    }
};

const PRESETS = [
    { name: 'Air Conditioner', watt: 1200 },
    { name: 'Refrigerator', watt: 150 },
    { name: 'LED TV', watt: 100 },
    { name: 'Electric Fan', watt: 50 },
    { name: 'Water Heater', watt: 2000 },
    { name: 'Microwave', watt: 800 },
    { name: 'Laptop', watt: 65 },
];

const dailyData = [
  { name: 'Mon', usage: 12.4 }, { name: 'Tue', usage: 14.8 }, { name: 'Wed', usage: 13.2 },
  { name: 'Thu', usage: 18.5 }, { name: 'Fri', usage: 15.1 }, { name: 'Sat', usage: 22.4 },
  { name: 'Sun', usage: 20.8 },
];

const monthlyData = [
  { name: 'Jan', usage: 480 }, { name: 'Feb', usage: 410 }, { name: 'Mar', usage: 650 },
  { name: 'Apr', usage: 820 }, { name: 'May', usage: 780 }, { name: 'Jun', usage: 520 },
];

interface MultiDeviceItem {
    id: number;
    name: string;
    watt: number;
    hours: number;
}

interface DashboardProps {
    isDarkMode: boolean;
    onToggleTheme: () => void;
    onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ isDarkMode, onToggleTheme, onLogout }) => {
    const [currentPage, setCurrentPage] = useState('dashboard');
    const [lang, setLang] = useState<'th' | 'en'>('th');
    const [calcMode, setCalcMode] = useState<'hours' | 'budget' | 'manual'>('hours');
    const [statsFrame, setStatsFrame] = useState<'daily' | 'monthly'>('daily');

    // Calculator Configuration
    const [calcDays, setCalcDays] = useState(30);
    const [unitRate, setUnitRate] = useState(4.5);
    const [calcMoney, setCalcMoney] = useState(1000);
    const [multiDevices, setMultiDevices] = useState<MultiDeviceItem[]>([
        { id: Date.now(), name: 'Air Conditioner', watt: 1200, hours: 8 }
    ]);

    const t = (key: string) => (langData[lang] as any)[key] || key;

    const navItems = [
        { id: 'dashboard', icon: 'fas fa-home', key: 'm1' },
        { id: 'devices', icon: 'fas fa-plug', key: 'm2' },
        { id: 'calculator', icon: 'fas fa-calculator', key: 'm3' },
        { id: 'budget', icon: 'fas fa-wallet', key: 'm4' },
        { id: 'stats', icon: 'fas fa-chart-line', key: 'm5' },
        { id: 'noti', icon: 'fas fa-bell', key: 'm6' },
        { id: 'tips', icon: 'fas fa-lightbulb', key: 'm7' },
        { id: 'compare', icon: 'fas fa-balance-scale', key: 'm8' },
        { id: 'settings', icon: 'fas fa-cog', key: 'm9' },
    ];

    const currentChartData = useMemo(() => statsFrame === 'daily' ? dailyData : monthlyData, [statsFrame]);

    const addMultiDevice = () => {
        setMultiDevices([...multiDevices, { id: Date.now(), name: 'New Appliance', watt: 100, hours: 1 }]);
    };

    const removeMultiDevice = (id: number) => {
        if (multiDevices.length > 1) setMultiDevices(multiDevices.filter(d => d.id !== id));
    };

    const updateMultiDevice = (id: number, field: keyof MultiDeviceItem, value: any) => {
        setMultiDevices(multiDevices.map(d => d.id === id ? { ...d, [field]: value } : d));
    };

    const grandTotalValue = useMemo(() => {
        let totalUnits = 0;
        multiDevices.forEach(d => totalUnits += (d.watt / 1000) * d.hours * calcDays);
        return totalUnits * unitRate;
    }, [multiDevices, calcDays, unitRate]);

    const getDeviceResults = (device: MultiDeviceItem) => {
        const units = (device.watt / 1000) * device.hours * calcDays;
        const cost = units * unitRate;
        return {
            cost: cost.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
            units: units.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
            dailyCost: (cost / calcDays).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 }),
            totalCombined: grandTotalValue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })
        };
    };

    const budgetResults = useMemo(() => {
        const d = multiDevices[0];
        const totalHrPossible = calcMoney / ((d.watt / 1000) * unitRate);
        return {
            possibleHr: totalHrPossible.toFixed(1),
            possibleDay: (totalHrPossible / 8).toFixed(1)
        };
    }, [multiDevices, calcMoney, unitRate]);

    const CustomTooltip = ({ active, payload, label }: TooltipProps<number, string>) => {
        if (active && payload && payload.length) {
            return (
                <div className="p-3 bg-white border border-light rounded-4 shadow-lg">
                    <p className="mb-1 fw-bold text-dark">{label}</p>
                    <p className="mb-0 text-primary text-lg">{payload[0].value} {statsFrame === 'daily' ? 'kWh' : 'kWh Total'}</p>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="dashboard-container" data-theme={isDarkMode ? 'dark' : 'light'}>
            {/* Sidebar */}
            <div className="sidebar flex flex-col justify-between">
                <div>
                    <div className="mb-5 ps-2">
                        <h4 className="fw-bold text-primary mb-1">EduEase</h4>
                        <span className="text-[10px] uppercase tracking-[0.3em] text-gray-400">Energy Management</span>
                    </div>
                    <nav>
                        {navItems.map(item => (
                            <button key={item.id} className={`nav-link ${currentPage === item.id ? 'active' : ''}`} onClick={() => setCurrentPage(item.id)}>
                                <i className={item.icon}></i> <span>{t(item.key)}</span>
                            </button>
                        ))}
                    </nav>
                </div>
                <div className="pt-4 border-top border-secondary-subtle">
                    <button onClick={onLogout} className="nav-link text-danger border-0 bg-transparent w-full text-start flex items-center gap-2 hover:bg-danger/10">
                        <i className="fas fa-sign-out-alt"></i> <span>{t('logout')}</span>
                    </button>
                </div>
            </div>

            <div className="main-content-dashboard">
                {/* Header */}
                <div className="d-flex justify-content-between align-items-center mb-5">
                    <div>
                        <h3 className="fw-bold mb-0">{t(navItems.find(n => n.id === currentPage)?.key || 'm1')}</h3>
                        <p className="text-muted small mb-0">Hello, Namyen User. Welcome back to your sector hub.</p>
                    </div>
                    <div className="d-flex gap-2">
                        <button className="btn btn-white border-0 rounded-pill px-4 shadow-sm fw-bold text-primary bg-white" onClick={() => setLang(lang === 'th' ? 'en' : 'th')}>
                            <i className="fas fa-globe me-2"></i>{lang.toUpperCase()}
                        </button>
                        <button className="btn btn-white border-0 rounded-circle shadow-sm p-3 bg-white" onClick={onToggleTheme}>
                            <i className={`fas ${isDarkMode ? 'fa-sun text-warning' : 'fa-moon text-primary'}`}></i>
                        </button>
                    </div>
                </div>

                {/* Dashboard Home */}
                {currentPage === 'dashboard' && (
                    <div className="page-content animate-fade-in">
                        <div className="row g-4 mb-4">
                            <div className="col-md-3"><div className="dashboard-card border-0 shadow-sm"><span className="label">{t('db1')}</span><span className="val text-3xl">฿ 1,250.40</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card border-0 shadow-sm"><span className="label">{t('db2')}</span><span className="val text-3xl text-success">{t('st_normal')}</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card border-0 shadow-sm"><span className="label">{t('db3')}</span><span className="val text-3xl">152 kWh</span></div></div>
                            <div className="col-md-3"><div className="dashboard-card border-0 shadow-sm"><span className="label">{t('db4')}</span><span className="val text-3xl text-danger">15 Jan 2026</span></div></div>
                        </div>
                        <div className="dashboard-card border-0 shadow-sm p-4">
                           <h6 className="fw-bold mb-4">Quick Insights</h6>
                           <div className="row g-4">
                               <div className="col-md-6 border-end">
                                   <div className="d-flex align-items-center gap-3">
                                       <div className="p-3 rounded-circle bg-primary-subtle text-primary"><i className="fas fa-bolt fa-lg"></i></div>
                                       <div>
                                           <span className="label block">Peak Usage Detected</span>
                                           <h5 className="fw-bold mb-0">Today @ 14:00 PM (2.4 kW)</h5>
                                       </div>
                                   </div>
                               </div>
                               <div className="col-md-6">
                                    <div className="d-flex align-items-center gap-3">
                                       <div className="p-3 rounded-circle bg-success-subtle text-success"><i className="fas fa-leaf fa-lg"></i></div>
                                       <div>
                                           <span className="label block">Efficiency Score</span>
                                           <h5 className="fw-bold mb-0">84/100 - Better than 70% neighbors</h5>
                                       </div>
                                   </div>
                               </div>
                           </div>
                        </div>
                    </div>
                )}

                {/* Calculator Section */}
                {currentPage === 'calculator' && (
                    <div className="page-content animate-fade-in">
                        {/* Global Settings */}
                        <div className="dashboard-card border-0 shadow-sm mb-4 p-4 bg-white/40">
                            <div className="row g-4 align-items-center">
                                <div className="col-md-3">
                                    <label className="label mb-2"><i className="fas fa-coins me-2"></i>{t('c_rate')}</label>
                                    <input type="number" step="0.1" className="form-control form-control-lg fw-bold" value={unitRate} onChange={(e) => setUnitRate(parseFloat(e.target.value) || 0)} />
                                </div>
                                <div className="col-md-3">
                                    <label className="label mb-2"><i className="fas fa-calendar-check me-2"></i>{t('c_days')}</label>
                                    <input type="number" className="form-control form-control-lg fw-bold" value={calcDays} onChange={(e) => setCalcDays(parseInt(e.target.value) || 0)} />
                                </div>
                                <div className="col-md-6 pt-3">
                                    <div className="d-flex gap-2">
                                        <button className={`btn flex-grow-1 py-3 rounded-4 fw-bold ${calcMode === 'hours' ? 'btn-primary' : 'btn-light'}`} onClick={() => setCalcMode('hours')}><i className="fas fa-clock me-2"></i>{t('c1')}</button>
                                        <button className={`btn flex-grow-1 py-3 rounded-4 fw-bold ${calcMode === 'budget' ? 'btn-primary' : 'btn-light'}`} onClick={() => setCalcMode('budget')}><i className="fas fa-wallet me-2"></i>{t('c2')}</button>
                                        <button className={`btn flex-grow-1 py-3 rounded-4 fw-bold ${calcMode === 'manual' ? 'btn-primary' : 'btn-light'}`} onClick={() => setCalcMode('manual')}><i className="fas fa-file-invoice-dollar me-2"></i>{t('c_manual')}</button>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="row g-4">
                            <div className="col-xl-8">
                                <div className="space-y-4">
                                    {calcMode === 'hours' && multiDevices.map((device) => {
                                        const res = getDeviceResults(device);
                                        return (
                                            <div key={device.id} className="dashboard-card border-0 shadow-sm p-4 overflow-hidden relative group">
                                                <div className="row g-4">
                                                    <div className="col-lg-6">
                                                        <div className="row g-3">
                                                            <div className="col-12">
                                                                <label className="label mb-2 text-primary fw-bold uppercase tracking-wider">{t('c_device_name')}</label>
                                                                <div className="d-flex gap-2">
                                                                    <select className="form-select form-select-lg border-2" value={PRESETS.find(p => p.watt === device.watt)?.name || 'Custom'}
                                                                        onChange={(e) => {
                                                                            const p = PRESETS.find(preset => preset.name === e.target.value);
                                                                            if(p) { updateMultiDevice(device.id, 'name', p.name); updateMultiDevice(device.id, 'watt', p.watt); }
                                                                        }}>
                                                                        {PRESETS.map(p => <option key={p.name} value={p.name}>{p.name} ({p.watt}W)</option>)}
                                                                        <option value="Custom">Custom / อื่นๆ</option>
                                                                    </select>
                                                                    <button className="btn btn-outline-danger px-4 rounded-3" onClick={() => removeMultiDevice(device.id)} disabled={multiDevices.length === 1}><i className="fas fa-times-circle"></i></button>
                                                                </div>
                                                            </div>
                                                            <div className="col-6">
                                                                <label className="label mb-2">{t('c_watts')}</label>
                                                                <input type="number" className="form-control" value={device.watt} onChange={(e) => updateMultiDevice(device.id, 'watt', parseInt(e.target.value) || 0)} />
                                                            </div>
                                                            <div className="col-6">
                                                                <label className="label mb-2">{t('c_hours')}</label>
                                                                <input type="number" step="0.5" className="form-control" value={device.hours} onChange={(e) => updateMultiDevice(device.id, 'hours', parseFloat(e.target.value) || 0)} />
                                                            </div>
                                                        </div>
                                                    </div>
                                                    <div className="col-lg-6 border-start ps-lg-5 d-flex flex-column justify-content-center bg-primary/5 rounded-4 p-4">
                                                        <div className="text-end">
                                                            <span className="label text-primary font-bold uppercase tracking-widest block mb-2">{t('c-total')} (ชิ้นนี้)</span>
                                                            <h1 className="fw-bold text-primary text-6xl mb-4 tracking-tighter">฿ {res.cost}</h1>
                                                            <div className="row g-3">
                                                                <div className="col-6">
                                                                    <small className="label block text-[11px] mb-1">การใช้พลังงานรวม</small>
                                                                    <span className="fw-bold text-2xl text-dark d-block">{res.units} <small className="text-muted text-sm">kWh</small></span>
                                                                </div>
                                                                <div className="col-6">
                                                                    <small className="label block text-[11px] mb-1">เฉลี่ยต่อวัน</small>
                                                                    <span className="fw-bold text-2xl text-dark d-block">฿ {res.dailyCost}</span>
                                                                </div>
                                                            </div>
                                                            <div className="mt-3 pt-3 border-top border-primary/10">
                                                                <span className="text-[10px] text-primary/60 font-bold uppercase">Total All Devices Combined: ฿ {res.totalCombined}</span>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                    {calcMode === 'budget' && (
                                        <div className="dashboard-card border-0 shadow-sm p-5 text-center bg-white">
                                            <div className="max-w-md mx-auto">
                                                <div className="p-4 bg-primary/10 rounded-circle w-20 h-20 flex items-center justify-center mx-auto mb-4">
                                                    <i className="fas fa-piggy-bank text-primary text-3xl"></i>
                                                </div>
                                                <h4 className="fw-bold mb-4">Smart Budget Optimizer</h4>
                                                <div className="mb-4 text-start">
                                                    <label className="label mb-2 text-primary font-bold">SET BUDGET (THB)</label>
                                                    <input type="number" className="form-control form-control-lg text-center fw-bold text-4xl py-4 border-2" value={calcMoney} onChange={(e) => setCalcMoney(parseFloat(e.target.value) || 0)} />
                                                </div>
                                                <div className="text-start">
                                                    <label className="label mb-2">TARGET DEVICE</label>
                                                    <select className="form-select form-select-lg border-2" value={multiDevices[0].watt} onChange={(e) => updateMultiDevice(multiDevices[0].id, 'watt', parseInt(e.target.value))}>
                                                        {PRESETS.map(p => <option key={p.name} value={p.watt}>{p.name}</option>)}
                                                    </select>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                    {calcMode === 'manual' && (
                                        <div className="dashboard-card border-0 shadow-sm p-5 bg-white">
                                            <h4 className="fw-bold mb-4"><i className="fas fa-receipt me-3 text-primary"></i>Manual Bill Record</h4>
                                            <div className="row g-4">
                                                <div className="col-md-6">
                                                    <label className="label mb-2">Previous Meter Reading</label>
                                                    <input type="number" className="form-control form-control-lg" placeholder="1025.5" />
                                                </div>
                                                <div className="col-md-6">
                                                    <label className="label mb-2">Current Meter Reading</label>
                                                    <input type="number" className="form-control form-control-lg" placeholder="1150.0" />
                                                </div>
                                                <div className="col-12">
                                                    <button className="btn btn-primary w-100 py-3 rounded-4 fw-bold">CALCULATE FROM METER</button>
                                                </div>
                                            </div>
                                            <div className="mt-5 pt-4 border-top">
                                                <h6 className="label font-bold mb-3">BILL HISTORY (SAMPLE)</h6>
                                                <div className="space-y-2">
                                                    {[
                                                        { m: 'December 2025', c: '฿ 1,450.00', u: '320 kWh' },
                                                        { m: 'November 2025', c: '฿ 1,320.50', u: '290 kWh' }
                                                    ].map((item, i) => (
                                                        <div key={i} className="d-flex justify-content-between p-3 bg-light rounded-3 align-items-center">
                                                            <span className="fw-bold text-dark">{item.m}</span>
                                                            <div className="text-end">
                                                                <div className="fw-bold text-primary">{item.c}</div>
                                                                <small className="text-muted">{item.u}</small>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                    {calcMode === 'hours' && (
                                        <button className="btn btn-primary w-100 py-4 rounded-4 fw-bold shadow-lg border-0 bg-primary/90 hover:bg-primary transition-all" onClick={addMultiDevice}>
                                            <i className="fas fa-plus-circle me-3"></i> {t('c_add')}
                                        </button>
                                    )}
                                </div>
                            </div>

                            <div className="col-xl-4">
                                <div className="dashboard-card h-100 bg-primary text-white border-0 shadow-2xl p-5 sticky-top overflow-hidden" style={{ top: '20px' }}>
                                    <div className="absolute top-0 right-0 p-5 opacity-10"><i className="fas fa-bolt text-9xl"></i></div>
                                    <h5 className="fw-bold mb-5 opacity-80 border-bottom border-white/20 pb-4 text-xs tracking-widest uppercase">{t('c-res')}</h5>
                                    {calcMode === 'hours' ? (
                                        <div className="animate-fade-in relative z-10">
                                            <span className="label text-white-50 block mb-2 text-sm">{t('c-total')}</span>
                                            <h1 className="fw-bold text-7xl tracking-tighter mb-5">฿ {grandTotalValue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</h1>

                                            <div className="space-y-6">
                                                <div className="p-4 rounded-4 bg-white/10 backdrop-blur-md border border-white/10">
                                                    <span className="label text-white-50 block text-[10px] uppercase tracking-widest mb-2">TOTAL ENERGY UNITS</span>
                                                    <h3 className="fw-bold text-5xl">{(grandTotalValue / unitRate).toLocaleString(undefined, { maximumFractionDigits: 1 })} <small className="text-lg opacity-60">kWh</small></h3>
                                                </div>

                                                <div className="p-4 rounded-4 bg-white/10 backdrop-blur-md border border-white/10">
                                                    <span className="label text-white-50 block text-[10px] uppercase tracking-widest mb-2">GRAND DAILY AVG</span>
                                                    <h3 className="fw-bold text-5xl">฿ {(grandTotalValue / calcDays).toLocaleString(undefined, { minimumFractionDigits: 2 })}</h3>
                                                </div>
                                            </div>

                                            <div className="mt-5 p-4 rounded-4 bg-yellow-400 text-dark flex items-center gap-3 shadow-xl">
                                                <div className="p-2 bg-dark/10 rounded-circle"><i className="fas fa-info-circle text-xl"></i></div>
                                                <div className="small leading-tight">
                                                    <b>Sector Insight:</b> Calculations based on {multiDevices.length} devices for {calcDays} days at standard ฿{unitRate}/unit rate.
                                                </div>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="animate-fade-in text-center py-5 relative z-10">
                                            <span className="label text-white-50 text-xl font-bold">LIMIT REACHED IN</span>
                                            <h1 className="fw-bold mt-3 text-8xl tracking-tighter">{budgetResults.possibleHr} <small className="text-3xl opacity-60">Hrs</small></h1>
                                            <div className="my-5 border-top border-white opacity-20"></div>
                                            <div className="p-4 rounded-4 bg-white/10">
                                                <span className="text-white-50 block text-xs uppercase tracking-widest mb-2">Sustainable Operating Window</span>
                                                <h2 className="fw-bold text-6xl tracking-tighter">{budgetResults.possibleDay} <small className="text-2xl">Days</small></h2>
                                            </div>
                                            <p className="mt-4 text-white-50 italic small opacity-60">* Assumes 8 hours daily nominal usage</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Stats Section */}
                {currentPage === 'stats' && (
                    <div className="page-content animate-fade-in">
                        <div className="row g-4 mb-4">
                            <div className="col-md-8">
                                <div className="dashboard-card border-0 shadow-sm p-4 h-100">
                                    <div className="d-flex justify-content-between align-items-center mb-5">
                                        <div>
                                            <h5 className="fw-bold mb-0">Usage Trend Analysis</h5>
                                            <span className="text-muted small">Dynamic load monitoring across sectors</span>
                                        </div>
                                        <div className="btn-group rounded-pill overflow-hidden border">
                                            <button className={`btn btn-sm px-4 ${statsFrame === 'daily' ? 'btn-primary' : 'btn-white'}`} onClick={() => setStatsFrame('daily')}>{t('s1')}</button>
                                            <button className={`btn btn-sm px-4 ${statsFrame === 'monthly' ? 'btn-primary' : 'btn-white'}`} onClick={() => setStatsFrame('monthly')}>{t('s2')}</button>
                                        </div>
                                    </div>
                                    <div style={{ width: '100%', height: '400px' }}>
                                        <ResponsiveContainer width="100%" height="100%">
                                            <AreaChart data={currentChartData}>
                                                <defs>
                                                    <linearGradient id="colorUsage" x1="0" y1="0" x2="0" y2="1">
                                                        <stop offset="5%" stopColor="var(--primary)" stopOpacity={0.4}/>
                                                        <stop offset="95%" stopColor="var(--primary)" stopOpacity={0}/>
                                                    </linearGradient>
