const PRESETS = [
    { name: 'Air Conditioner', watt: 1200 },
    { name: 'Refrigerator', watt: 150 },
    { name: 'LED TV', watt: 100 },
    { name: 'Electric Fan', watt: 50 },
    { name: 'Water Heater', watt: 2000 },
    { name: 'Microwave', watt: 800 },
];

const COLORS = ['#6f42c1', '#10b981', '#f59e0b', '#3b82f6', '#ef4444', '#8b5cf6'];

interface DashboardProps {
    isDarkMode: boolean;
    onToggleTheme: () => void;
    onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ isDarkMode, onToggleTheme, onLogout }) => {
