                            <div className="col-md-3"><div className="dashboard-card border-0 shadow-sm"><span className="label">{t('db3')}</span><span className="val text-4xl mt-2">{totalStats.units.toFixed(1)} <small className="text-sm">kWh</small></span></div></div>
                            <div className="col-md-3"><div className="dashboard-card border-0 shadow-sm"><span className="label">{t('db4')}</span><span className="val text-4xl mt-2 text-danger">15 Jan 26</span></div></div>
                        </div>
                        <div className="row g-4">
                            <div className="col-lg-8">
                                <div className="dashboard-card border-0 shadow-sm p-4 h-100">
