                                    <div key={dev.id} className="row g-4">
                                        <div className="col-lg-4">
                                            <div className="dashboard-card border-0 shadow-sm p-4 h-100">
                                                <h6 className="fw-bold mb-4">Device Config: {dev.name}</h6>
