                                                    <div><label className="label">Power (Watts)</label><input type="number" className="form-control" value={dev.watt} onChange={(e) => updateDevice(dev.id, 'watt', +e.target.value)} /></div>
                                                    <div><label className="label">Usage (Hrs/Day)</label><input type="number" className="form-control" value={dev.hours} onChange={(e) => updateDevice(dev.id, 'hours', +e.target.value)} /></div>
                                                    <div><label className="label">Category</label><input type="text" className="form-control" value={dev.category} onChange={(e) => updateDevice(dev.id, 'category', e.target.value)} /></div>
                                                    <button className="btn btn-danger w-100 mt-4 rounded-3" onClick={() => {removeDevice(dev.id); setSelectedDeviceId(null);}}>Delete Device</button>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="col-lg-8">
                                            <div className="dashboard-card border-0 shadow-sm p-4 h-100 bg-primary text-white">
                                                <h6 className="fw-bold mb-5 opacity-80 uppercase tracking-widest">Device Economics</h6>
                                                <div className="row g-4">
                                                    <div className="col-md-6 border-end border-white/10">
                                                        <span className="label text-white/50">{t('dv5')} (Monthly)</span>
                                                        <h1 className="fw-bold text-6xl mt-2">฿ {((dev.watt/1000)*dev.hours*calcDays*unitRate).toLocaleString()}</h1>
                                                    </div>
                                                    <div className="col-md-6 ps-md-4">
                                                        <span className="label text-white/50">Daily Running Cost</span>
                                                        <h2 className="fw-bold text-4xl mt-2">฿ {((dev.watt/1000)*dev.hours*unitRate).toFixed(2)}</h2>
                                                        <div className="mt-4 p-3 bg-white/10 rounded-3 border border-white/10">
                                                            <div className="label text-white/50">Monthly Load</div>
                                                            <div className="fw-bold text-2xl">{(dev.watt/1000*dev.hours*calcDays).toFixed(1)} kWh</div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                {/* 3. Electricity Bill Calculator */}
                {currentPage === 'calculator' && (
                    <div className="page-content animate-fade-in">
                        <div className="dashboard-card border-0 shadow-sm p-4 mb-4">
                            <div className="row g-3 align-items-center">
                                <div className="col-md-4"><label className="label mb-2">{t('c_rate')}</label><input type="number" step="0.1" className="form-control fw-bold" value={unitRate} onChange={(e) => setUnitRate(+e.target.value)} /></div>
                                <div className="col-md-4"><label className="label mb-2">{t('c_days')}</label><input type="number" className="form-control fw-bold" value={calcDays} onChange={(e) => setCalcDays(+e.target.value)} /></div>
                                <div className="col-md-4 d-flex gap-2 pt-3">
                                    <button className={`btn flex-grow-1 fw-bold ${calcMode === 'hours' ? 'btn-primary' : 'btn-light'}`} onClick={() => setCalcMode('hours')}>Hours Mode</button>
                                    <button className={`btn flex-grow-1 fw-bold ${calcMode === 'budget' ? 'btn-primary' : 'btn-light'}`} onClick={() => setCalcMode('budget')}>Budget Mode</button>
                                </div>
                            </div>
                        </div>
                        <div className="row g-4">
                            <div className="col-lg-8">
                                <div className="space-y-4">
                                    {multiDevices.map(dev => (
                                        <div key={dev.id} className="dashboard-card border-0 shadow-sm p-4">
                                            <div className="row g-3">
                                                <div className="col-md-5"><label className="label">{t('c_device_name')}</label><input type="text" className="form-control" value={dev.name} onChange={(e) => updateDevice(dev.id, 'name', e.target.value)} /></div>
                                                <div className="col-md-3"><label className="label">{t('c_watts')}</label><input type="number" className="form-control" value={dev.watt} onChange={(e) => updateDevice(dev.id, 'watt', +e.target.value)} /></div>
                                                <div className="col-md-4"><label className="label">{t('c_hours')}</label><input type="number" className="form-control" value={dev.hours} onChange={(e) => updateDevice(dev.id, 'hours', +e.target.value)} /></div>
                                            </div>
                                        </div>
                                    ))}
                                    <button className="btn btn-outline-primary w-100 py-3 rounded-4 fw-bold border-2" onClick={addDevice}><i className="fas fa-plus-circle me-2"></i> {t('c_add')}</button>
                                </div>
                            </div>
                            <div className="col-lg-4">
                                <div className="dashboard-card h-100 bg-primary text-white p-5 border-0 shadow-lg d-flex flex-column justify-content-center">
