                                                    <div className="fw-bold text-3xl">{totalStats.units.toFixed(1)} <small className="text-sm">kWh</small></div>
                                                </div>
                                                <div className="p-3 bg-white/10 rounded-3">
                                                    <div className="label text-white/50">Grand Daily Average</div>
                                                    <div className="fw-bold text-3xl">฿ {totalStats.daily.toFixed(2)}</div>
                                                </div>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="animate-fade-in text-center">
