                                    </div>
                                    <div className="p-3 border rounded-4 d-flex justify-content-between align-items-center">
                                        <div className="fw-bold"><i className="fas fa-palette me-3 text-primary"></i>Dark Interface</div>
                                        <div className="form-check form-switch"><input className="form-check-input" type="checkbox" checked={isDarkMode} onChange={onToggleTheme} /></div>
                                    </div>
                                    <div className="p-3 border rounded-4 d-flex justify-content-between align-items-center cursor-pointer">
                                        <div className="fw-bold"><i className="fas fa-lock me-3 text-primary"></i>Security Node Settings</div>
