                                    </div>
                                    <hr className="my-5" />
                                    <button className="btn btn-danger w-100 py-3 rounded-4 fw-bold shadow-sm" onClick={onLogout}><i className="fas fa-sign-out-alt me-2"></i> {t('logout')}</button>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

