                                        <span className="label text-xs">{t('db1')}</span>
                                        <span className="val text-5xl mt-2 font-display text-primary">฿ {totalStats.cost.toLocaleString()}</span>
                                        <div className="mt-2 text-xs text-muted">Estimate for {calcDays} days</div>
                                    </div>
                                </div>
                                <div className="col-md-3">
                                    <div className="dashboard-card border-0 shadow-sm p-4 text-center">
                                        <span className="label text-xs">{t('db2')}</span>
                                        <span className={`val text-5xl mt-2 font-display ${totalStats.cost > globalBudget ? 'text-danger' : 'text-success'}`}>
