                                                            <div className="font-bold text-sm">Budget Sync</div>
                                                            <div className="text-[10px] opacity-70">Control your spending</div>
                                                        </div>
                                                    </div>
                                                    <i className="fas fa-chevron-right opacity-50"></i>
                                                </button>
                                            </div>
                                        </div>
                                        <div className="mt-5 p-4 bg-light rounded-2xl">
                                            <div className="flex items-center gap-2 mb-2">
                                                <i className="fas fa-bolt text-warning"></i>
                                                <span className="font-bold text-[11px] uppercase tracking-widest text-muted">System Alert</span>
                                            </div>
                                            <p className="small text-muted mb-0 leading-relaxed">Grid stability is high. Suggesting eco-mode for Cooling Nodes between 14:00 - 16:00 today.</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* 2. Electrical Devices Page */}
                    {currentPage === 'devices' && (
                        <div className="animate-fade-in">
                            {!selectedDeviceId ? (
