                                    <div className="col-12 d-flex justify-content-between align-items-center mb-2">
                                        <h5 className="fw-bold mb-0 font-display">Manage Active Grid Nodes</h5>
                                        <button className="btn btn-primary rounded-pill px-4 py-2 fw-bold text-sm" onClick={addDevice}><i className="fas fa-plus me-2"></i> {t('dv2')}</button>
                                    </div>
                                    {multiDevices.map(dev => {
                                        const cost = (dev.watt / 1000) * dev.hours * calcDays * unitRate;
                                        const statusColor = dev.status === 'active' ? 'bg-success' : 'bg-warning';
                                        return (
                                            <div key={dev.id} className="col-md-4">
                                                <div className="dashboard-card border-0 shadow-sm p-4 h-100 hover:shadow-2xl hover:translate-y-[-5px] transition-all cursor-pointer group" onClick={() => setSelectedDeviceId(dev.id)}>
                                                    <div className="d-flex justify-content-between align-items-start mb-4">
                                                        <div className="p-3 bg-primary-subtle rounded-2xl text-primary group-hover:bg-primary group-hover:text-white transition-all">
                                                            <i className={`fas ${dev.category === 'Cooling' ? 'fa-snowflake' : dev.category === 'Kitchen' ? 'fa-utensils' : 'fa-plug'} fa-lg`}></i>
                                                        </div>
                                                        <div className={`px-2 py-1 rounded-pill text-[9px] font-bold text-white uppercase tracking-tighter ${statusColor}`}>{dev.status}</div>
                                                    </div>
                                                    <h6 className="fw-bold mb-1 font-display text-lg">{dev.name}</h6>
                                                    <div className="text-muted text-xs mb-4">{dev.category} Sector</div>
                                                    <div className="mb-4">
                                                        <div className="label text-[10px] mb-1">Energy Impact</div>
                                                        <div className="val text-2xl text-primary">฿ {cost.toLocaleString()} <small className="text-muted text-xs font-normal">/ mo</small></div>
                                                    </div>
                                                    <div className="progress rounded-full" style={{ height: '6px' }}>
                                                        <div className="progress-bar bg-primary" style={{ width: `${Math.min((cost/globalBudget)*100, 100)}%` }}></div>
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            ) : (
                                <div className="animate-fade-in">
                                    <button className="btn btn-link text-primary p-0 mb-5 fw-bold text-sm no-underline hover:underline" onClick={() => setSelectedDeviceId(null)}><i className="fas fa-arrow-left me-2"></i> Back to All Nodes</button>
                                    {multiDevices.filter(d => d.id === selectedDeviceId).map(dev => (
                                        <div key={dev.id} className="row g-4">
                                            <div className="col-lg-4">
                                                <div className="dashboard-card border-0 shadow-sm p-5 h-100">
                                                    <h5 className="fw-bold mb-5 font-display border-bottom pb-4">Node Configuration</h5>
                                                    <div className="space-y-4">
                                                        <div><label className="label text-[10px] block mb-2">{t('c_device_name')}</label><input type="text" className="form-control form-control-lg border-2 rounded-2xl" value={dev.name} onChange={(e) => updateDevice(dev.id, 'name', e.target.value)} /></div>
                                                        <div className="row g-3">
                                                            <div className="col-6"><label className="label text-[10px] block mb-2">{t('c_watts')}</label><input type="number" className="form-control form-control-lg border-2 rounded-2xl" value={dev.watt} onChange={(e) => updateDevice(dev.id, 'watt', +e.target.value)} /></div>
                                                            <div className="col-6"><label className="label text-[10px] block mb-2">{t('c_hours')}</label><input type="number" className="form-control form-control-lg border-2 rounded-2xl" value={dev.hours} onChange={(e) => updateDevice(dev.id, 'hours', +e.target.value)} /></div>
                                                        </div>
                                                        <div><label className="label text-[10px] block mb-2">Operational Sector</label><select className="form-select form-control-lg border-2 rounded-2xl" value={dev.category} onChange={(e) => updateDevice(dev.id, 'category', e.target.value)}><option>Cooling</option><option>Kitchen</option><option>Bathroom</option><option>Entertainment</option><option>Misc</option></select></div>
                                                        <div className="pt-4 flex gap-2">
                                                            <button className="btn btn-primary flex-grow rounded-2xl py-3 fw-bold" onClick={() => setSelectedDeviceId(null)}>SAVE CHANGES</button>
                                                            <button className="btn btn-outline-danger rounded-2xl px-4" onClick={() => {removeDevice(dev.id); setSelectedDeviceId(null);}}><i className="fas fa-trash"></i></button>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="col-lg-8">
                                                <div className="dashboard-card border-0 shadow-lg p-5 h-100 bg-primary text-white overflow-hidden relative">
                                                    <div className="absolute -bottom-20 -right-20 opacity-10"><i className="fas fa-bolt text-[300px]"></i></div>
                                                    <h6 className="fw-bold mb-5 uppercase tracking-[0.3em] opacity-60 text-xs">Energy Intelligence: {dev.name}</h6>
                                                    <div className="row g-5 relative z-10">
