                                                            <div className="mb-5">
                                                                <span className="label text-white/50 text-[10px] block mb-1">Monthly Cost Index</span>
                                                                <h1 className="fw-bold text-8xl tracking-tighter mb-0 font-display">฿ {((dev.watt/1000)*dev.hours*calcDays*unitRate).toLocaleString()}</h1>
                                                            </div>
                                                            <div className="p-4 bg-white/10 rounded-3xl border border-white/10">
                                                                <div className="label text-white/50 text-[9px] block mb-1">Annual Forecast</div>
                                                                <h3 className="fw-bold text-3xl font-display">฿ {((dev.watt/1000)*dev.hours*365*unitRate).toLocaleString()}</h3>
                                                            </div>
                                                        </div>
