                                                                <div>
                                                                    <span className="label text-white/50 text-[10px] block mb-1">Daily Running Cost</span>
                                                                    <h2 className="fw-bold text-5xl font-display">฿ {((dev.watt/1000)*dev.hours*unitRate).toFixed(2)}</h2>
