                                                                <div className="row g-4">
                                                                    <div className="col-6">
                                                                        <div className="label text-white/50 text-[9px] block mb-1">Grid Load (kWh)</div>
                                                                        <div className="fw-bold text-2xl">{(dev.watt/1000*dev.hours*calcDays).toFixed(1)}</div>
                                                                    </div>
