    const t = (key: string) => (langData[lang] as any)[key] || key;

    const totalStats = useMemo(() => {
        let units = 0;
        multiDevices.forEach(d => units += (d.watt / 1000) * d.hours * calcDays);
        const cost = units * unitRate;
        return { units, cost, daily: cost / calcDays };
