        if (multiDevices.some(d => d.hours === 24 && d.watt > 1000)) {
            detections.push({ type: 'Logic Bug', msg: 'Continuous high load detected on Bathroom Node. Potential thermostat fault.' });
        }
        if (totalStats.cost > globalBudget * 1.2) {
            detections.push({ type: 'Anomaly', msg: 'Usage forecast exceeds budget by 20%. Suggesting grid balancing.' });
        }
        return detections;
