                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {currentPage === 'settings' && (
                        <div className="animate-fade-in max-w-2xl mx-auto">
                            <div className="dashboard-card border-0 shadow-2xl p-5 rounded-[50px] relative overflow-hidden">
