                                    </div>
                                    <div className="p-4 bg-light rounded-[30px] d-flex justify-content-between align-items-center hover:bg-white border-2 border-transparent hover:border-primary transition-all cursor-pointer">
                                        <div className="flex items-center gap-4"><i className="fas fa-palette text-primary text-xl"></i><span className="fw-bold font-display text-lg">Dark Mode Protocol</span></div>
                                        <div className="form-check form-switch mb-0"><input className="form-check-input scale-150" type="checkbox" checked={isDarkMode} onChange={onToggleTheme} /></div>
                                    </div>
                                    <div className="p-4 bg-light rounded-[30px] d-flex justify-content-between align-items-center hover:bg-white border-2 border-transparent hover:border-primary transition-all cursor-pointer">
                                        <div className="flex items-center gap-4"><i className="fas fa-key text-primary text-xl"></i><span className="fw-bold font-display text-lg">Security Settings</span></div>
                                        <i className="fas fa-chevron-right text-muted opacity-30"></i>
                                    </div>
                                    <div className="pt-5 border-top mt-5">
                                        <button className="btn btn-danger w-100 py-4 rounded-[40px] fw-bold shadow-2xl shadow-danger/20 text-xs uppercase tracking-[0.4em]" onClick={onLogout}><i className="fas fa-power-off me-3"></i> TERMINATE SECTOR ACCESS</button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </section>
            </main>
        </div>
    );
};

