                                                        <div className="label text-white/50 text-xs mb-1">Grid Energy Flow</div>
                                                        <div className="fw-bold text-3xl font-display mono-font">{totalStats.units.toFixed(1)} <small className="text-sm opacity-50">kWh</small></div>
                                                    </div>
                                                </div>
                                            ) : (
                                                <div className="animate-fade-in">
                                                    <span className="label text-white/50 block mb-4">Target Budget Cap</span>
                                                    <input type="number" className="form-control bg-transparent border-white/20 text-white text-center fw-bold text-7xl py-4 border-2 rounded-[40px] mb-5 mono-font focus:border-white/50" value={globalBudget || ''} onChange={(e) => handleNumericInput(e.target.value, setGlobalBudget)} />
                                                    <div className="d-flex align-items-center justify-content-center flex-column">
                                                        <h1 className="fw-bold text-[10rem] tracking-tighter leading-none neon-glow">{totalStats.daily > 0 ? Math.floor(globalBudget / totalStats.daily) : '∞'}</h1>
                                                        <div className="text-2xl font-bold opacity-60 uppercase tracking-[0.3em] font-display">Available Days</div>
                                                    </div>
                                                </div>
                                            )}
                                        </div>

                                        <div className="mt-auto pt-5 border-top border-white/10">
                                            <div className="row g-3">
                                                <div className="col-6">
                                                    <div className="p-3 bg-white/5 rounded-2xl">
                                                        <span className="label text-white/40 text-[9px] block mb-1">Units per Day</span>
                                                        <div className="fw-bold text-xl mono-font">{(totalStats.units / calcDays).toFixed(2)}</div>
                                                    </div>
                                                </div>
                                                <div className="col-6">
                                                    <div className="p-3 bg-white/5 rounded-2xl">
                                                        <span className="label text-white/40 text-[9px] block mb-1">Cost per Hour</span>
                                                        <div className="fw-bold text-xl mono-font">฿{(totalStats.cost / (calcDays * 24)).toFixed(2)}</div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Other sections remain fully functional but hidden to save response space as requested */}
                    {['dashboard', 'devices', 'budget', 'stats', 'noti', 'tips', 'compare', 'settings'].includes(currentPage) === false && (
                        <div className="animate-fade-in py-10 text-center opacity-60 font-display">
                            Module "{t(navItems.find(n => n.id === currentPage)?.key || '')}" rendering...
                        </div>
                    )}

                </div>
            </main>
        </div>
    );
};

export default Dashboard;

