            powerFactor: 0.94, maintenanceLogs: [
                { date: '2025-01-10', task: 'Filter cleaning', status: 'Completed' },
                { date: '2024-11-22', task: 'Coolant recharge', status: 'Completed' }
            ]
        },
        { 
            id: 2, name: 'Refrigerator', watt: 150, hours: 24, budget: 600, category: 'Kitchen', status: 'active',
            powerFactor: 0.92, maintenanceLogs: [
                { date: '2024-12-01', task: 'Coil inspection', status: 'Completed' }
            ]
        },
        { 
            id: 3, name: 'Water Heater', watt: 2000, hours: 1, budget: 800, category: 'Bathroom', status: 'standby',
            powerFactor: 0.98, maintenanceLogs: [
                { date: '2025-01-15', task: 'Safety valve test', status: 'Completed' }
            ]
        },
        { 
            id: 4, name: 'LED TV', watt: 100, hours: 6, budget: 300, category: 'Entertainment', status: 'active',
            powerFactor: 0.95, maintenanceLogs: []
