        const findings = [];
        const repetition = multiDevices.find(d => d.hours >= 24 && d.watt > 100);
        if (repetition) findings.push({ type: 'Logic Repetition', msg: `Device '${repetition.name}' suspended.` });
        if (totalStats.cost > globalBudget) findings.push({ type: 'Budget Anomaly', msg: `Exceeding limit.` });
        return findings;
