                <header className="d-flex justify-content-between align-items-center mb-5">
                    <div>
                        <h2 className="fw-bold mb-0 font-display text-3xl">{t(navItems.find(n => n.id === currentPage)?.key || 'm1')}</h2>
                        <p className="text-muted text-[10px] font-medium uppercase tracking-[0.2em]">{isDarkMode ? 'Neural Dark Interface' : 'Active Grid Terminal'}</p>
                    </div>
                    <div className="d-flex gap-3">
                        <div className="flex items-center gap-2 px-3 py-1.5 bg-light rounded-full border shadow-sm">
                            <span className="neural-pulse"></span>
                            <span className="text-[9px] font-bold uppercase tracking-widest text-muted">AI Monitor: {aiDetections.length > 0 ? 'ALERT' : 'STABLE'}</span>
