        { id: 1, name: 'Air Conditioner', watt: 1200, hours: 8, category: 'Cooling', status: 'active', pf: 0.94 },
        { id: 2, name: 'Smart Fridge', watt: 150, hours: 24, category: 'Kitchen', status: 'active', pf: 0.91 },
        { id: 3, name: 'Water Heater', watt: 2000, hours: 1, category: 'Bathroom', status: 'standby', pf: 0.98 },
        { id: 4, name: 'Cinema Display', watt: 180, hours: 6, category: 'Entertainment', status: 'active', pf: 0.95 },
        { id: 5, name: 'Gaming Rig', watt: 450, hours: 4, category: 'Entertainment', status: 'standby', pf: 0.89 },
