    // System Config
    const [calcDays, setCalcDays] = useState(30);
    const [unitRate, setUnitRate] = useState(4.5);
    const [globalBudget, setGlobalBudget] = useState(3500);

    // Initial Data
    const [multiDevices, setMultiDevices] = useState([
        { id: 1, name: 'Air Conditioner', watt: 1200, hours: 8, category: 'Cooling', status: 'active', pf: 0.94 },
        { id: 2, name: 'Smart Fridge', watt: 150, hours: 24, category: 'Kitchen', status: 'active', pf: 0.91 },
