    // Computed Analytics
    const analytics = useMemo(() => {
        let totalUnits = 0;
        multiDevices.forEach(d => totalUnits += (d.watt / 1000) * d.hours * calcDays);
        const totalCost = totalUnits * unitRate;
        const burnRate = totalCost / calcDays;
        const budgetRemaining = globalBudget - totalCost;

        // Simple TOU Simulation (assuming 30% of use can be shifted to Off-Peak at half rate)
        const touOnPeakRate = 5.8;
        const touOffPeakRate = 2.6;
        const touCost = totalUnits * (0.7 * touOnPeakRate + 0.3 * touOffPeakRate);

        return { totalUnits, totalCost, burnRate, budgetRemaining, touCost };
    }, [multiDevices, calcDays, unitRate, globalBudget]);

