                                        { label: t('set_security'), val: 'Active', type: 'info' }
                                    ].map((row, i) => (
                                        <div key={i} className="p-5 bg-light rounded-3xl flex justify-between items-center transition-all hover:bg-white hover:shadow-md border border-transparent hover:border-light">
                                            <span className="font-bold text-sm tracking-tight">{row.label}</span>
                                            {row.type === 'select' ? (
                                                <select className="form-select border-0 bg-transparent w-fit font-bold text-primary text-sm p-0" value={row.val} onChange={e => row.onChange(e.target.value)}>
