import React, { useState, useEffect, useCallback } from 'react';
import LoginForm from './components/LoginForm';
import Dashboard from './components/Dashboard';
import { HOUSES } from './constants';

const getStoredTheme = (key: string, defaultValue: boolean): boolean => {
  const saved = localStorage.getItem(key);
  return saved !== null ? saved === 'true' : defaultValue;
};

const App: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [username, setUsername] = useState('');

  const [loginDarkMode, setLoginDarkMode] = useState<boolean>(() => 
    getStoredTheme('loginDarkMode', true)
  );
  const [dashboardDarkMode, setDashboardDarkMode] = useState<boolean>(() => 
    getStoredTheme('dashboardDarkMode', false)
  );

  useEffect(() => {
    localStorage.setItem('loginDarkMode', String(loginDarkMode));
  }, [loginDarkMode]);

  useEffect(() => {
    localStorage.setItem('dashboardDarkMode', String(dashboardDarkMode));
  }, [dashboardDarkMode]);

  useEffect(() => {
    const currentDarkMode = isLoggedIn ? dashboardDarkMode : loginDarkMode;
    const body = document.body;
    body.setAttribute('data-theme', currentDarkMode ? 'dark' : 'light');

    if (isLoggedIn) {
      body.style.backgroundColor = currentDarkMode ? '#0b1437' : '#f4f7fe';
    } else {
      body.style.backgroundColor = '#000';
    }
  }, [isLoggedIn, loginDarkMode, dashboardDarkMode]);

  const activeHouse = HOUSES[activeIndex];

  const handleNext = useCallback(() => {
    setActiveIndex((prev) => (prev + 1) % HOUSES.length);
  }, []);

  const handlePrev = useCallback(() => {
    setActiveIndex((prev) => (prev - 1 + HOUSES.length) % HOUSES.length);
  }, []);

  const toggleLoginTheme = () => setLoginDarkMode((prev) => !prev);
  const toggleDashboardTheme = () => setDashboardDarkMode((prev) => !prev);

  const handleLoginSuccess = (user: string) => {
    setUsername(user);
    setIsLoggedIn(true);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUsername('');
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isLoggedIn) {
        if (e.key === 'ArrowRight') handleNext();
        if (e.key === 'ArrowLeft') handlePrev();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNext, handlePrev, isLoggedIn]);

  if (isLoggedIn) {
    return (
      <Dashboard 
        isDarkMode={dashboardDarkMode} 
        onToggleTheme={toggleDashboardTheme} 
        onLogout={handleLogout} 
      />
    );
  }

  const textColor = loginDarkMode ? 'text-white' : 'text-slate-900';
  const navTextColor = loginDarkMode ? 'text-white/40 hover:text-white' : 'text-slate-500 hover:text-emerald-600';

  return (
    <div className="relative h-screen w-full overflow-hidden bg-black flex flex-col">
      {/* Background Slider - Full Screen Immersive */}
      <div className="absolute inset-0 z-0 overflow-hidden">
        {HOUSES.map((house, idx) => (
          <div
            key={house.id}
            className={`absolute inset-0 bg-transition ${
              idx === activeIndex 
                ? 'opacity-100 scale-100 blur-0' 
                : 'opacity-0 scale-110 blur-sm'
            }`}
            style={{
              backgroundImage: `url(${house.imageUrl})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
            }}
          />
        ))}
        {/* Professional Overlays */}
        <div className={`absolute inset-0 ${loginDarkMode ? 'bg-black/60' : 'bg-white/40'} backdrop-blur-[2px] transition-all duration-1000`} />
        <div className="absolute inset-0 vignette-overlay" />
        <div className="scanline" />
      </div>

      {/* Main Content Layer */}
      <div className="relative z-10 flex flex-col h-full">
        {/* Header */}
        <header className="w-full px-6 py-6 md:px-12 md:py-10 flex justify-between items-center">
          <div className="flex items-center gap-4 group cursor-pointer">
            <div className={`w-10 h-10 flex items-center justify-center border ${loginDarkMode ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-emerald-600 bg-white/50'} rounded-xl transition-all duration-500 group-hover:border-emerald-500 group-hover:shadow-[0_0_15px_rgba(16,185,129,0.3)]`}>
               <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(16,185,129,1)]" />
            </div>
            <div>
              <span className={`${textColor} block font-display text-sm font-bold tracking-[0.4em] uppercase leading-none`}>EduEase Energy</span>
              <span className="text-[8px] technical-label text-emerald-500 font-bold uppercase mt-1 opacity-60">Property Management Portal</span>
            </div>
          </div>

          <div className="flex items-center gap-4 md:gap-10">
            <nav className="hidden lg:flex gap-10">
              {['Global Systems', 'Active Nodes', 'Emergency Protokol'].map((link) => (
                <a key={link} href="#" className={`${navTextColor} transition-all text-[9px] technical-label font-bold uppercase tracking-[0.3em]`}>{link}</a>
              ))}
            </nav>

            <button 
              onClick={toggleLoginTheme}
              className={`w-10 h-10 rounded-xl border flex items-center justify-center transition-all duration-300 ${loginDarkMode ? 'border-white/10 bg-white/5 hover:bg-white/10 text-yellow-400' : 'border-slate-200 bg-white/50 hover:bg-white text-slate-700'} shadow-sm`}
            >
              {loginDarkMode ? (
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 2a1 1 0 011 1v1a1 1 0 11-2 0V3a1 1 0 011-1zm4 8a4 4 0 11-8 0 4 4 0 018 0zm-.464 4.95l.707.707a1 1 0 001.414-1.414l-.707-.707a1 1 0 00-1.414 1.414zm2.12-10.607a1 1 0 010 1.414l-.706.707a1 1 0 11-1.414-1.414l.707-.707a1 1 0 011.414 0zM17 11a1 1 0 100-2h-1a1 1 0 100 2h1zm-7 4a1 1 0 011 1v1a1 1 0 11-2 0v-1a1 1 0 011-1zM5.05 6.464A1 1 0 106.465 5.05l-.708-.707a1 1 0 00-1.414 1.414l.707.707zm1.414 8.486l-.707.707a1 1 0 01-1.414-1.414l.707-.707a1 1 0 011.414 1.414zM4 11a1 1 0 100-2H3a1 1 0 000 2h1z" clipRule="evenodd" /></svg>
              ) : (
                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M17.293 13.293A8 8 0 016.707 2.707a8.001 8.001 0 1010.586 10.586z" /></svg>
              )}
            </button>
