        {/* Footer */}
        <footer className="w-full px-6 pb-10 md:px-12 md:pb-16 flex flex-col md:flex-row justify-between items-center md:items-end gap-10">
          <div className="w-full md:max-w-xl text-center md:text-left">
            <div key={activeHouse.id} className="animate-fade-in">
              <div className="flex items-center justify-center md:justify-start gap-3 mb-2">
                <span className="w-4 h-[1px] bg-emerald-500 opacity-50"></span>
                <h3 className="technical-label text-emerald-500 text-[8px] font-bold uppercase">SEC-INFO: NODE_{activeHouse.id}</h3>
              </div>
              <p className={`${textColor} font-display text-2xl md:text-4xl font-light tracking-tight mb-2 uppercase`}>{activeHouse.name}</p>
              <p className={`${loginDarkMode ? 'text-white/40' : 'text-slate-500'} text-[10px] font-bold technical-label uppercase tracking-widest`}>{activeHouse.location}</p>
            </div>
          </div>

          <div className="flex flex-col items-center md:items-end gap-6">
            <div className="flex gap-4">
              <button onClick={handlePrev} className={`group w-12 h-12 rounded-full border flex items-center justify-center transition-all ${loginDarkMode ? 'border-white/10 hover:border-emerald-500 hover:bg-emerald-500/10' : 'border-slate-200 hover:border-emerald-600 hover:bg-emerald-600/5'} ${textColor}`}>
                <svg className="w-5 h-5 group-active:scale-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15 19l-7-7 7-7" /></svg>
              </button>
              <button onClick={handleNext} className={`group w-12 h-12 rounded-full border flex items-center justify-center transition-all ${loginDarkMode ? 'border-white/10 hover:border-emerald-500 hover:bg-emerald-500/10' : 'border-slate-200 hover:border-emerald-600 hover:bg-emerald-600/5'} ${textColor}`}>
                <svg className="w-5 h-5 group-active:scale-90 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 5l7 7-7 7" /></svg>
              </button>
