            <div className="flex items-end gap-2">
               <span className={`${loginDarkMode ? 'text-white/10' : 'text-slate-200'} font-display text-6xl md:text-8xl font-thin tracking-tighter leading-none`}>
                 {String(activeIndex + 1).padStart(2, '0')}
               </span>
               <span className={`${loginDarkMode ? 'text-white/5' : 'text-slate-100'} technical-label text-xs font-bold mb-2`}>/05</span>
            </div>
          </div>
        </footer>
      </div>

      {/* Aesthetic Grain Layer */}
      <div className="absolute inset-0 pointer-events-none opacity-[0.04] z-[60] mix-blend-overlay" style={{backgroundImage: 'url(https://grainy-gradients.vercel.app/noise.svg)'}} />
    </div>
  );
};

export default App;

