                                <div className="row g-4 flex-nowrap md:flex-wrap">
                                    {compareDevices.map((dev, di) => {
                                        const energyMonth = (dev.watt / 1000) * dev.hours * calcDays;
                                        const isBestPF = dev.pf === Math.max(...compareDevices.map(d => d.pf));

                                        return (
                                            <div key={dev.id} className="col-11 col-md-6 col-lg-4">
                                                <div className={`dashboard-card p-6 h-100 flex flex-col relative transition-all border-2 ${isBestPF ? 'border-emerald-500/20 shadow-emerald-500/10' : 'border-light'}`}>
                                                    {isBestPF && (
                                                        <div className="absolute top-4 right-4"><span className="badge bg-emerald-500 text-white rounded-full text-[8px] font-bold uppercase py-1.5 px-3"><i className="fas fa-star me-1"></i> {t('comp_best')}</span></div>
                                                    )}
                                                    <div className="p-4 bg-light rounded-[2rem] w-fit mb-6">
                                                        <i className={`fas ${dev.category === 'Cooling' ? 'fa-snowflake' : 'fa-plug'} text-primary text-xl`}></i>
                                                    </div>
                                                    <h4 className="font-bold text-xl mb-1">{dev.name}</h4>
                                                    <p className="text-[10px] text-muted uppercase font-bold tracking-widest mb-8">{dev.category} Sector</p>

                                                    <div className="space-y-6 mt-auto">
                                                        {[
                                                            { label: t('comp_metric_load'), val: `${dev.watt} W` },
                                                            { label: t('comp_metric_energy'), val: `${energyMonth.toFixed(1)} kWh`, color: 'text-primary' },
                                                            { label: t('comp_metric_cost'), val: `฿${(energyMonth * unitRate).toLocaleString(undefined, {maximumFractionDigits: 0})}`, color: 'text-emerald-500' },
                                                            { label: t('comp_metric_pf'), val: dev.pf, type: 'pf' }
                                                        ].map((m, mi) => (
                                                            <div key={mi} className="p-4 bg-light rounded-3xl border border-transparent hover:border-primary/10 transition-all">
                                                                <span className="text-[9px] font-bold text-muted uppercase block mb-1">{m.label}</span>
                                                                <div className={`text-xl font-bold mono-font ${m.color || ''}`}>
                                                                    {m.val}
                                                                    {m.type === 'pf' && <span className={`inline-block w-2 h-2 rounded-full ms-2 ${Number(m.val) > 0.9 ? 'bg-emerald-500' : 'bg-amber-500'} animate-pulse`}></span>}
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>

                        <div className="p-8 bg-card border-top border-light flex justify-center">
                            <button className="btn btn-primary rounded-full px-12 py-3 font-bold text-sm uppercase tracking-widest shadow-lg" onClick={() => setShowComparisonView(false)}>Done</button>
                        </div>
                    </div>
                </div>
            )}

            {/* Node Config Overlay */}
            {selectedDeviceId && !showComparisonView && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[9998] flex justify-end">
                    <div className="w-full max-w-xl bg-body h-full shadow-2xl p-6 md:p-10 animate-slide-left overflow-y-auto">
                        <div className="flex justify-between items-center mb-8">
                            <h3 className="font-display font-bold text-xl md:text-2xl">{t('node_config_title')}</h3>
                            <button className="btn btn-light rounded-2xl p-3" onClick={() => setSelectedDeviceId(null)}><i className="fas fa-times"></i></button>
                        </div>
                        {multiDevices.find(d => d.id === selectedDeviceId) && (() => {
                            const d = multiDevices.find(d => d.id === selectedDeviceId)!;
                            return (
                                <div className="space-y-8">
                                    <div className="p-6 bg-primary/5 rounded-[2rem] border border-primary/10">
                                        <input type="text" className="form-control text-2xl font-bold border-0 bg-transparent p-0 mb-4" value={d.name} readOnly />
                                        <div className="row g-3">
                                            <div className="col-6">
                                                <label className="label text-[10px] block mb-2">{t('node_watt')}</label>
                                                <div className="p-3 bg-white rounded-2xl font-bold mono-font text-xl">{d.watt}W</div>
                                            </div>
                                            <div className="col-6">
                                                <label className="label text-[10px] block mb-2">{t('node_pf')}</label>
                                                <div className="p-3 bg-white rounded-2xl font-bold mono-font text-xl text-emerald-500">{d.pf}</div>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="p-6 bg-light rounded-[2.5rem]">
                                        <h6 className="label text-[10px] mb-6">{t('node_history_title')}</h6>
                                        <div className="h-[200px] flex items-center justify-center text-muted italic text-sm">Telemetry data active...</div>
                                    </div>
                                    <button className="btn btn-primary w-full rounded-[1.5rem] py-4 font-bold text-sm uppercase tracking-widest shadow-lg" onClick={() => setSelectedDeviceId(null)}>{t('node_auth')}</button>
                                </div>
                            );
                        })()}
                    </div>
                </div>
            )}
        </div>
    );
};

export default Dashboard;

