import React, { useState, useEffect, useCallback } from 'react';
import LoginForm from './components/LoginForm';
import Dashboard from './components/Dashboard';
import { HOUSES } from './constants';

const getStoredTheme = (key: string, defaultValue: boolean): boolean => {
  const saved = localStorage.getItem(key);
  return saved !== null ? saved === 'true' : defaultValue;
};

const App: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [username, setUsername] = useState('');

  const [loginDarkMode, setLoginDarkMode] = useState<boolean>(() => 
    getStoredTheme('loginDarkMode', true)
  );
  const [dashboardDarkMode, setDashboardDarkMode] = useState<boolean>(() => 
    getStoredTheme('dashboardDarkMode', false)
  );

  useEffect(() => {
    localStorage.setItem('loginDarkMode', String(loginDarkMode));
  }, [loginDarkMode]);

  useEffect(() => {
    localStorage.setItem('dashboardDarkMode', String(dashboardDarkMode));
  }, [dashboardDarkMode]);

  useEffect(() => {
    const currentDarkMode = isLoggedIn ? dashboardDarkMode : loginDarkMode;
    document.body.setAttribute('data-theme', currentDarkMode ? 'dark' : 'light');
    if (!isLoggedIn) {
      document.body.style.backgroundColor = '#000';
    } else {
      document.body.style.backgroundColor = currentDarkMode ? '#0b1437' : '#f4f7fe';
    }
  }, [isLoggedIn, loginDarkMode, dashboardDarkMode]);

  const activeHouse = HOUSES[activeIndex];

  const handleNext = useCallback(() => {
    setActiveIndex((prev) => (prev + 1) % HOUSES.length);
  }, []);

  const handlePrev = useCallback(() => {
    setActiveIndex((prev) => (prev - 1 + HOUSES.length) % HOUSES.length);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isLoggedIn) {
        if (e.key === 'ArrowRight') handleNext();
        if (e.key === 'ArrowLeft') handlePrev();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleNext, handlePrev, isLoggedIn]);

  if (isLoggedIn) {
    return (
      <Dashboard 
        isDarkMode={dashboardDarkMode} 
        onToggleTheme={() => setDashboardDarkMode(!dashboardDarkMode)} 
        onLogout={() => setIsLoggedIn(false)} 
      />
    );
  }

  const textColor = loginDarkMode ? 'text-white' : 'text-slate-900';

  return (
    <div className="relative h-screen w-full overflow-hidden bg-black flex flex-col">
      {/* Background Slider */}
      <div className="absolute inset-0 z-0 overflow-hidden">
        {HOUSES.map((house, idx) => (
          <div
            key={house.id}
            className={`absolute inset-0 bg-transition ${
              idx === activeIndex ? 'opacity-100 scale-100' : 'opacity-0 scale-110'
            }`}
            style={{
              backgroundImage: `url(${house.imageUrl})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
            }}
          />
        ))}
        {/* Overlays */}
        <div className={`absolute inset-0 ${loginDarkMode ? 'bg-black/60' : 'bg-white/40'} backdrop-blur-[2px] transition-all duration-1000`} />
        <div className="absolute inset-0 scanline" />
      </div>

      <div className="relative z-10 flex flex-col h-full">
        <header className="px-8 py-10 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className={`w-8 h-8 border-2 ${loginDarkMode ? 'border-emerald-500/40' : 'border-emerald-600'} flex items-center justify-center`}>
              <div className="w-2 h-2 bg-emerald-500 animate-pulse" />
            </div>
            <span className={`${textColor} font-display text-sm font-bold tracking-[0.4em] uppercase`}>EduEase Energy</span>
          </div>
          <button 
            onClick={() => setLoginDarkMode(!loginDarkMode)}
            className={`w-10 h-10 rounded-xl border flex items-center justify-center ${loginDarkMode ? 'border-white/10 bg-white/5 text-yellow-400' : 'border-slate-200 bg-white/50 text-slate-700'}`}
          >
            {loginDarkMode ? <i className="fas fa-sun"></i> : <i className="fas fa-moon"></i>}
          </button>
        </header>

        <main className="flex-grow flex items-center justify-center">
           <LoginForm 
              selectedHouseName={activeHouse.name} 
              onLogin={(user) => { setUsername(user); setIsLoggedIn(true); }}
              isDarkMode={loginDarkMode}
           />
        </main>

        <footer className="px-10 pb-16 flex justify-between items-end">
          <div key={activeHouse.id} className="animate-fade-in">
            <h3 className="technical-label text-emerald-500 text-[8px] font-bold uppercase mb-1">SEC_ID: {activeHouse.id}</h3>
            <p className={`${textColor} font-display text-3xl font-light tracking-tight mb-1 uppercase`}>{activeHouse.name}</p>
            <p className={`${loginDarkMode ? 'text-white/30' : 'text-slate-500'} text-[10px] font-bold technical-label uppercase tracking-widest`}>{activeHouse.location}</p>
          </div>

          <div className="flex flex-col items-end">
            <div className="flex gap-2 mb-4">
              <button onClick={handlePrev} className="w-10 h-10 rounded-full border border-white/10 flex items-center justify-center text-white hover:bg-emerald-500 transition-all"><i className="fas fa-chevron-left"></i></button>
              <button onClick={handleNext} className="w-10 h-10 rounded-full border border-white/10 flex items-center justify-center text-white hover:bg-emerald-500 transition-all"><i className="fas fa-chevron-right"></i></button>
            </div>
            <span className="text-white/10 font-display text-7xl font-thin leading-none">{String(activeIndex + 1).padStart(2, '0')}</span>
          </div>
        </footer>
      </div>
    </div>
  );
};

export default App;

