    const [multiDevices, setMultiDevices] = useState<Device[]>([
        { id: 1, name: 'Air Conditioner', watt: 1200, hours: 8, category: 'Cooling', status: 'active', pf: 0.94 },
        { id: 2, name: 'Fridge Pro', watt: 150, hours: 24, category: 'Kitchen', status: 'active', pf: 0.91 },
        { id: 3, name: 'Master Heater', watt: 2000, hours: 1, category: 'Bathroom', status: 'standby', pf: 0.98 },
        { id: 4, name: 'Cinema Display', watt: 180, hours: 6, category: 'Entertainment', status: 'active', pf: 0.95 },
        { id: 5, name: 'Workstation Node', watt: 450, hours: 4, category: 'Entertainment', status: 'active', pf: 0.89 },
    ]);

    const t = (key: string) => (langData[lang] as any)[key] || key;

    const filteredDevices = useMemo(() => {
        return multiDevices.filter(d => 
            (activeCategory === 'All' || d.category === activeCategory) &&
            d.name.toLowerCase().includes(searchTerm.toLowerCase())
        );
    }, [multiDevices, activeCategory, searchTerm]);

    const compareDevices = useMemo(() => {
        return multiDevices.filter(d => compareDeviceIds.includes(d.id));
    }, [multiDevices, compareDeviceIds]);

    const runAiScan = async () => {
        if (isScanning) return;
        setIsScanning(true);
