const CATEGORIES = ['Cooling', 'Kitchen', 'Bathroom', 'Entertainment', 'Misc'];

interface MaintenanceLog {
    date: string;
    event: string;
    technician: string;
}

interface HistoricalPoint {
    time: string;
    load: number;
}

interface Device {
    id: number;
    name: string;
    watt: number;
    hours: number;
    category: string;
    status: string;
    pf: number;
    logs: MaintenanceLog[];
    history: HistoricalPoint[];
}

const generateMockHistory = (baseWatt: number): HistoricalPoint[] => {
    return Array.from({ length: 24 }, (_, i) => ({
        time: `${i}:00`,
        load: Math.floor(baseWatt * (0.8 + Math.random() * 0.4))
    }));
};

