                        <button className="btn btn-white border-0 rounded-2xl px-4 shadow-sm font-bold text-xs text-primary bg-white h-[42px]" onClick={() => setLang(lang === 'th' ? 'en' : 'th')}>{lang.toUpperCase()}</button>
                        <button className="btn btn-white border-0 rounded-2xl shadow-sm px-3 bg-white h-[42px]" onClick={onToggleTheme}>
                            <i className={`fas ${isDarkMode ? 'fa-sun text-warning' : 'fa-moon text-primary'}`}></i>
                        </button>
                    </div>
                </header>

                <div className="page-content">
                    {currentPage === 'dashboard' && (
                        <div className="animate-fade-in">
                            <div className="row g-4 mb-8">
                                {[
                                    { label: t('stat_est_monthly'), val: '฿3,450', icon: 'fa-coins', color: 'text-primary' },
                                    { label: t('stat_total_load'), val: '14.2 kWh', icon: 'fa-bolt', color: 'text-emerald-500' },
                                    { label: t('stat_credit_health'), val: 'Optimal', icon: 'fa-shield-alt', color: 'text-emerald-500' }
                                ].map((stat, i) => (
                                    <div key={i} className="col-12 col-md-4 animate-slide-up" style={{ animationDelay: `${i*100}ms` }}>
                                        <div className="dashboard-card p-6 flex flex-col">
                                            <span className="text-[10px] font-bold text-muted uppercase tracking-widest mb-2">{stat.label}</span>
                                            <div className="flex justify-between items-center">
                                                <span className={`text-2xl font-bold ${stat.color} technical-label`}>{stat.val}</span>
                                                <i className={`fas ${stat.icon} ${stat.color} opacity-20`}></i>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                            <div className="dashboard-card p-8 h-[350px]">
                                <h5 className="font-bold mb-8 font-display">Grid Performance</h5>
                                <ResponsiveContainer>
                                    <AreaChart data={[{n:'Mon', v:10}, {n:'Tue', v:15}, {n:'Wed', v:12}, {n:'Thu', v:20}, {n:'Fri', v:18}]}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                        <XAxis dataKey="n" axisLine={false} tickLine={false} />
                                        <YAxis axisLine={false} tickLine={false} />
                                        <Tooltip />
                                        <Area type="monotone" dataKey="v" stroke="var(--primary)" fill="var(--primary)" fillOpacity={0.1} strokeWidth={3} />
                                    </AreaChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                    )}

                    {currentPage === 'devices' && (
                        <div className="animate-fade-in">
                            <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-8">
                                <div className="flex gap-2 w-full md:w-auto">
                                    <input type="text" className="form-control border-0 bg-white shadow-sm rounded-2xl px-4 py-3 text-sm" placeholder={t('search')} value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                                    {compareDeviceIds.length > 0 && (
                                        <button className="btn btn-primary rounded-2xl px-4 font-bold text-xs uppercase shadow-lg" onClick={() => setShowComparisonView(true)}>
                                            {t('node_compare_btn')} ({compareDeviceIds.length})
                                        </button>
                                    )}
                                </div>
                            </div>
                            <div className="row g-4">
                                {filteredDevices.map((dev, i) => (
                                    <div key={dev.id} className="col-12 col-md-6 col-lg-4 animate-slide-up" style={{ animationDelay: `${i*50}ms` }}>
                                        <div onClick={() => setSelectedDeviceId(dev.id)} className={`dashboard-card p-6 cursor-pointer relative overflow-hidden transition-all ${compareDeviceIds.includes(dev.id) ? 'ring-2 ring-primary' : ''}`}>
                                            <button onClick={(e) => { e.stopPropagation(); setCompareDeviceIds(p => p.includes(dev.id) ? p.filter(id => id !== dev.id) : [...p, dev.id]); }} className={`absolute top-4 left-4 w-8 h-8 rounded-lg flex items-center justify-center ${compareDeviceIds.includes(dev.id) ? 'bg-primary text-white' : 'bg-white shadow-sm text-primary'}`}>
                                                <i className={`fas ${compareDeviceIds.includes(dev.id) ? 'fa-check' : 'fa-plus'} text-[10px]`}></i>
                                            </button>
                                            <div className="p-4 bg-primary/5 text-primary rounded-2xl w-fit mb-4 mt-6"><i className="fas fa-plug text-xl"></i></div>
                                            <h5 className="font-bold mb-1">{dev.name}</h5>
                                            <p className="text-[10px] text-muted uppercase font-bold tracking-widest mb-6">{dev.category}</p>
                                            <div className="flex justify-between items-end pt-4 border-t">
                                                <div className="technical-label text-primary font-bold">฿{((dev.watt/1000)*dev.hours*30*4.5).toFixed(0)}</div>
                                                <div className="text-[10px] text-muted font-bold">{dev.watt}W</div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {currentPage === 'noti' && (
                        <div className="animate-fade-in max-w-3xl mx-auto">
                            <div className="flex justify-between items-center mb-8">
                                <h4 className="font-display font-bold text-2xl">{t('alert_log_title')}</h4>
                                <button onClick={runAiScan} className="btn btn-primary rounded-xl px-4 py-2 text-xs font-bold uppercase shadow-lg shadow-primary/20">
                                    {isScanning ? <i className="fas fa-spinner animate-spin"></i> : <i className="fas fa-brain"></i>} {t('alert_ai_scan')}
                                </button>
                            </div>
                            <div className="space-y-4">
                                {aiAlerts.map((n, i) => (
                                    <div key={i} className={`dashboard-card border-l-[6px] border-${n.severity === 'danger' ? 'red-500' : 'amber-500'} p-6 flex gap-4 animate-slide-up`}>
                                        <div className={`p-4 rounded-3xl bg-${n.severity === 'danger' ? 'red' : 'amber'}-500/10 text-${n.severity === 'danger' ? 'red' : 'amber'}-500`}><i className={`fas ${n.icon} text-xl`}></i></div>
                                        <div>
                                            <h6 className="font-bold mb-1">{n.title}</h6>
                                            <p className="text-muted text-xs leading-relaxed mb-0">{n.desc}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </main>

            {/* --- FULL SCREEN OVERLAYS --- */}

            {showComparisonView && (
                <div className="full-screen-overlay">
                    <div className="modal-content-box animate-slide-up">
                        <div className="p-8 md:p-12 flex justify-between items-center border-b bg-white dark:bg-[#111c44]">
                            <div>
                                <h3 className="font-display font-bold text-2xl md:text-3xl mb-1">{t('comp_title')}</h3>
                                <p className="text-[10px] text-muted font-bold uppercase tracking-widest">{t('node_comparing').replace('{n}', compareDevices.length.toString())}</p>
                            </div>
                            <button className="w-12 h-12 rounded-full bg-light flex items-center justify-center" onClick={() => setShowComparisonView(false)}>
                                <i className="fas fa-times"></i>
                            </button>
                        </div>
                        <div className="flex-grow overflow-auto p-8 md:p-12 bg-body">
                            <div className="row g-4">
                                {compareDevices.map(dev => (
                                    <div key={dev.id} className="col-12 col-md-6 col-lg-4">
                                        <div className="dashboard-card p-8 border-2 border-primary/10 shadow-xl flex flex-col h-100">
                                            <div className="p-4 bg-primary/5 text-primary rounded-3xl w-fit mb-6"><i className="fas fa-plug text-2xl"></i></div>
                                            <h4 className="font-bold text-xl mb-1">{dev.name}</h4>
                                            <p className="text-[10px] text-muted uppercase font-bold tracking-widest mb-8">{dev.category}</p>
                                            <div className="space-y-6 mt-auto">
                                                <div className="p-4 bg-light rounded-2xl"><span className="text-[9px] font-bold text-muted block mb-1">ELECTRICAL LOAD</span><div className="text-xl font-bold technical-label">{dev.watt} W</div></div>
                                                <div className="p-4 bg-light rounded-2xl"><span className="text-[9px] font-bold text-muted block mb-1">EST. MONTHLY COST</span><div className="text-xl font-bold technical-label text-emerald-500">฿{((dev.watt/1000)*dev.hours*30*4.5).toFixed(0)}</div></div>
                                                <div className="p-4 bg-light rounded-2xl"><span className="text-[9px] font-bold text-muted block mb-1">EFFICIENCY (PF)</span><div className="text-xl font-bold technical-label text-primary">{dev.pf}</div></div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                        <div className="p-8 bg-white dark:bg-[#111c44] border-t flex justify-center">
                            <button className="btn btn-primary rounded-full px-12 py-3 font-bold uppercase tracking-widest shadow-xl" onClick={() => setShowComparisonView(false)}>Close Benchmark</button>
                        </div>
                    </div>
                </div>
            )}

            {selectedDeviceId && !showComparisonView && (
                <div className="full-screen-overlay justify-end">
                    <div className="w-full max-w-2xl bg-body h-full shadow-2xl p-8 md:p-12 animate-slide-left overflow-y-auto custom-scrollbar">
                        <div className="flex justify-between items-center mb-10">
                            <h3 className="font-display font-bold text-2xl">{t('node_config_title')}</h3>
                            <button className="w-10 h-10 rounded-xl bg-light flex items-center justify-center" onClick={() => setSelectedDeviceId(null)}><i className="fas fa-times"></i></button>
                        </div>
                        {multiDevices.find(d => d.id === selectedDeviceId) && (() => {
                            const d = multiDevices.find(d => d.id === selectedDeviceId)!;
                            return (
                                <div className="space-y-10">
                                    <div className="p-8 bg-primary/5 rounded-[2.5rem] border border-primary/10">
                                        <div className="flex justify-between items-start mb-6">
                                            <div>
                                                <h4 className="text-2xl font-bold mb-1">{d.name}</h4>
                                                <p className="text-[10px] font-bold text-primary uppercase tracking-widest">{d.category} Sector</p>
                                            </div>
                                            <div className={`px-3 py-1 rounded-full text-[9px] font-bold uppercase ${d.status === 'active' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-amber-500/10 text-amber-500'}`}>
                                                {d.status}
                                            </div>
                                        </div>
                                        <div className="row g-4">
                                            <div className="col-6">
                                                <label className="text-[10px] font-bold text-muted uppercase block mb-2">{t('node_watt')}</label>
                                                <div className="p-4 bg-white rounded-2xl font-bold technical-label text-xl">{d.watt}W</div>
                                            </div>
                                            <div className="col-6">
                                                <label className="text-[10px] font-bold text-muted uppercase block mb-2">POWER FACTOR</label>
                                                <div className="p-4 bg-white rounded-2xl font-bold technical-label text-xl text-emerald-500">{d.pf}</div>
                                            </div>
                                        </div>
                                    </div>

                                    <div>
                                        <h5 className="text-[11px] font-bold uppercase tracking-[0.2em] mb-4 text-muted">{t('node_history_title')}</h5>
                                        <div className="p-6 bg-white rounded-[2rem] h-[220px]">
                                            <ResponsiveContainer width="100%" height="100%">
                                                <LineChart data={d.history}>
                                                    <CartesianGrid strokeDasharray="3 3" vertical={false} opacity={0.1} />
                                                    <XAxis dataKey="time" axisLine={false} tickLine={false} tick={{fontSize: 8}} interval={3} />
                                                    <YAxis axisLine={false} tickLine={false} tick={{fontSize: 8}} />
                                                    <Tooltip 
                                                        contentStyle={{ 
                                                            borderRadius: '16px', 
                                                            border: 'none', 
                                                            boxShadow: '0 10px 25px rgba(0,0,0,0.1)',
                                                            fontSize: '10px',
                                                            fontFamily: 'JetBrains Mono'
                                                        }} 
                                                    />
                                                    <Line type="monotone" dataKey="load" stroke="var(--primary)" strokeWidth={3} dot={false} />
                                                </LineChart>
                                            </ResponsiveContainer>
                                        </div>
                                    </div>

                                    <div>
                                        <h5 className="text-[11px] font-bold uppercase tracking-[0.2em] mb-4 text-muted">{t('node_maintenance')}</h5>
                                        <div className="space-y-3">
                                            {d.logs.length > 0 ? d.logs.map((log, li) => (
                                                <div key={li} className="p-4 bg-white rounded-2xl flex justify-between items-center border border-light">
                                                    <div>
                                                        <p className="text-xs font-bold mb-0">{log.event}</p>
                                                        <p className="text-[9px] text-muted mb-0">{log.technician}</p>
                                                    </div>
                                                    <span className="technical-label text-[9px] font-bold text-primary">{log.date}</span>
                                                </div>
                                            )) : (
                                                <div className="p-10 text-center bg-light rounded-3xl opacity-40">
                                                    <i className="fas fa-clipboard-list mb-3 text-2xl"></i>
                                                    <p className="text-[10px] font-bold uppercase tracking-widest">No Recent Logs</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    <button className="btn btn-primary w-full rounded-2xl py-4 font-bold uppercase tracking-widest shadow-lg mt-6" onClick={() => setSelectedDeviceId(null)}>{t('node_auth')}</button>
                                </div>
                            );
                        })()}
                    </div>
                </div>
            )}
        </div>
    );
};

export default Dashboard;
